function esc(s) {
  return String(s ?? '').replace(/[&<>"']/g, m => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;'
  }[m]));
}
function toast(t) { const e=document.createElement('div'); e.className='toast'; e.textContent=t; document.body.appendChild(e); setTimeout(()=>e.remove(),1800); }
// hxModal: `body` is raw HTML — callers must escape all user-controlled values with esc() before building the body string. Do not pass untrusted raw text directly.
function hxModal({title,body,confirmLabel='Submit',cancelLabel='Cancel',onConfirm,onCancel}={}) {document.getElementById('hx-modal')?.remove();const el=document.createElement('div');el.id='hx-modal';el.className='hx-modal-overlay';el.setAttribute('role','dialog');el.setAttribute('aria-modal','true');el.innerHTML=`<div class="hx-modal-panel">${title?`<h3 class="hx-modal-title">${esc(title)}</h3>`:''}<div class="hx-modal-body">${body||''}</div><div class="hx-modal-actions"><button class="primary hx-modal-confirm">${esc(confirmLabel)}</button><button class="hx-modal-cancel">${esc(cancelLabel)}</button></div></div>`;document.body.appendChild(el);const close=()=>{el.remove();document.removeEventListener('keydown',onKey);};const onKey=e=>{if(e.key==='Escape'){close();if(onCancel)onCancel();}};document.addEventListener('keydown',onKey);el.querySelector('.hx-modal-confirm').onclick=()=>{if(onConfirm)onConfirm(close);};el.querySelector('.hx-modal-cancel').onclick=()=>{close();if(onCancel)onCancel();};el.addEventListener('click',e=>{if(e.target===el){close();if(onCancel)onCancel();}});setTimeout(()=>el.querySelector('textarea,input')?.focus(),50);return close;}
// D-145B: advisory-mode owner token, sent alongside x-humanx-user wherever it
// is already sent. Empty string when absent (old stored users, or the
// backend secret not configured yet) — no endpoint rejects on this being
// missing/empty in this patch.
function headers(){return{'content-type':'application/json','x-humanx-user':user?.id||'','x-humanx-owner-token':user?.ownerToken||''}}
function adminToken(){return localStorage.getItem(LS_ADMIN)||''}
function adminHeaders(){return {...headers(),'x-humanx-admin':adminToken()}}
async function api(path,opts={}){const r=await fetch(API+path,{...opts,headers:{...headers(),...(opts.headers||{})}});const data=await r.json().catch(()=>({}));if(!r.ok)throw new Error(data.message||data.error||'Request failed');return data}
function localUser(){let u=JSON.parse(localStorage.getItem(LS_USER)||'null');if(!u){u={id:'usr_'+crypto.randomUUID().replaceAll('-','').slice(0,18),handle:'anon-'+Math.random().toString(36).slice(2,8)};localStorage.setItem(LS_USER,JSON.stringify(u))}return u}
// D-148A: idempotent session bootstrap. Closes the boot-race window by
// letting any owner-sensitive call site await session resolution before
// firing its request — concurrent callers share one in-flight promise, so
// calling this many times (once per call site, every time) is always safe
// and cheap. Merges the resolved user/owner_token into local state and
// localStorage only — never logs or returns the token value. If the
// session call fails for any reason, the failure is swallowed: the app
// keeps working advisory-only with whatever (possibly absent) ownerToken
// was already stored, exactly as it did before this patch.
let _sessionBootstrapPromise = null;
async function ensureSession(){
  if (!user) user = localUser();
  if (!_sessionBootstrapPromise) {
    _sessionBootstrapPromise = (async () => {
      try {
        const s = await api('/api/session', { method: 'POST', body: JSON.stringify(user) });
        if (s.user) user = { ...user, ...s.user };
        if (s.owner_token) user.ownerToken = s.owner_token;
        localStorage.setItem(LS_USER, JSON.stringify(user));
      } catch (_) {
        // advisory-only — a failed bootstrap must never block the caller
      }
    })();
  }
  return _sessionBootstrapPromise;
}
function safeHttpUrl(url){const s=String(url||'').trim();if(!s)return null;try{const u=new URL(s);if(u.protocol==='http:'||u.protocol==='https:')return u.href;return null;}catch(_){return null;}}
function sourceLink(url){const raw=String(url||'').trim();if(!raw)return`<p class="small ev-no-source">no source provided</p>`;const safe=safeHttpUrl(raw);if(safe){const e=esc(safe);return`<p class="small source"><a href="${e}" target="_blank" rel="noopener noreferrer">${e}</a></p>`;}return`<p class="small ev-bad-source">${esc(raw)} <span class="ev-bad-source-note">not clickable — not a valid web address</span></p>`;}
function cleanStance(v){v=String(v||'support').toLowerCase().trim();return v==='pressure'?'pressure':'support'}
function cleanClaimLabel(s){return String(s||'').replace(/\s*[—-]\s*this statement reflects reality consistently enough to survive evidence and repeatable pressure testing\.?/ig,'').replace(/\s*[—-]\s*X\s*$/,'').trim()}
function isFullBeliefProfile(s){return String(s?.source||'').includes('standalone-humanx-belief-engine')||String(s?.engineVersion||'').includes('humanx-belief-engine')||String(s?.label||'').includes('Belief Engine Profile')}
function parseAnalysis(text){try{const o=JSON.parse(String(text||''));if(o&&typeof o==='object'&&(o.verdict||o.strongest_support||o.strongest_pressure||o.missing_tests))return o}catch{}return null}
function shortText(s,n=420){s=String(s||'').trim();return s.length>n?s.slice(0,n)+'…':s}
function looksLikeJson(s){const t=String(s||'').trim();if(t.length<30)return false;if(/^[\[{]/.test(t)&&/[":,]/.test(t.slice(0,100)))return true;if(t.split('":').length>4)return true;if(/runpack_version|evidence_score|aip_version|strongest_support|packet_type/.test(t))return true;return false;}
function evidenceBodyHtml(text,maxChars=300){const t=String(text||'').trim();if(!t)return'';if(looksLikeJson(t)){const preview=t.replace(/[{}\[\],"]/g,' ').replace(/\s+/g,' ').trim().slice(0,120);return`<div class="ev-json-body"><span class="pill ev-json-chip">AI / JSON output</span><p class="small ev-body-preview">${esc(preview)}…</p><details class="ev-body-details"><summary>Show full text</summary><pre class="ev-body-full">${esc(t)}</pre></details></div>`;}return`<p class="small ev-body-text">${esc(shortText(t,maxChars))}</p>`;}
function inspectLongText(value,limit=320){const t=String(value||'').trim();if(!t)return'';if(t.length<=limit)return esc(t);return`${esc(t.slice(0,limit))}…<details class="inspect-long-details"><summary class="inspect-long-toggle">Show full text</summary><pre class="inspect-long-pre">${esc(t)}</pre></details>`;}
function listBits(arr){return Array.isArray(arr)?`<ul>${arr.slice(0,4).map(x=>`<li>${esc(x)}</li>`).join('')}</ul>`:''}
// D-140C: hash route for the public, no-auth profile view. Checked on every
// boot and on hashchange — never gates the rest of boot() since the public
// profile route needs no session/graph/claims state of its own.
function parsePublicProfileHash(){const m=String(location.hash||'').match(/^#\/u\/([^/?#]+)/);return m?decodeURIComponent(m[1]):null}
// D-143B: direct /u/:slug path is now served (with OG meta tags) by the
// Worker — this just lets the SPA recognize that path too, in addition to
// the existing #/u/:slug hash. Hash takes priority if somehow both are present.
function parsePublicProfilePath(){const m=String(location.pathname||'').match(/^\/u\/([^/?#]+)\/?$/);return m?decodeURIComponent(m[1]):null}
function resolvePublicProfileSlug(){return parsePublicProfileHash()||parsePublicProfilePath()}
// D-187B: detect /c/:id direct claim link — mirrors parsePublicProfilePath().
function parseDirectClaimPath(){const m=String(location.pathname||'').match(/^\/c\/([^/?#]+)\/?$/);return m?decodeURIComponent(m[1]):null}
function applyHashRoute(){const slug=parsePublicProfileHash();if(slug){publicProfileSlug=slug;mode='publicProfile';render()}else if(mode==='publicProfile'){mode='home';render()}}
window.addEventListener('hashchange',applyHashRoute);
async function boot(){user=localUser();document.getElementById('who').textContent=user.handle;const initialSlug=resolvePublicProfileSlug();const initialClaimId=parseDirectClaimPath();if(initialSlug){publicProfileSlug=initialSlug;mode='publicProfile'}try{const h=await api('/api/health');live=h.mode==='d1-live';setStatus(live?'Live':'Demo mode',live);await ensureSession();document.getElementById('who').textContent=user.handle;document.getElementById('tab-review').style.display=adminToken()?'':'none';loadMe().catch(()=>{});await Promise.all([loadGraphStatus(),loadClaims(false)]);if(initialClaimId){lastModeBeforeStudy='arena';mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await selectClaim(initialClaimId)}else{render()}}catch(e){setStatus('Backend unreachable',false,true);renderError(e)}}

// D-136C: account panel (anonymous/verified state + invite-code redeem).
// Reuses the existing x-humanx-user identity — never mints a new user id,
// never touches admin token state, never creates invite codes from the public UI.
let accountUser=null;
let accountPanelOpen=false;
async function loadMe(){await ensureSession();try{const data=await api('/api/me');accountUser=data.user||null}catch(_){accountUser=null}updateWhoBadge();renderAccountPanel();return accountUser}
function updateWhoBadge(){const el=document.getElementById('who');if(!el)return;if(accountUser&&accountUser.verified){el.textContent=accountUser.display_name||accountUser.handle||'verified';el.classList.add('who-verified')}else{el.textContent='◎ Invite';el.classList.remove('who-verified')}}
function toggleAccountPanel(){accountPanelOpen=!accountPanelOpen;if(accountPanelOpen)loadMe().catch(()=>{});renderAccountPanel()}
function accountPanelHtml(){const verified=!!(accountUser&&accountUser.verified);const handle=esc((accountUser&&accountUser.handle)||user?.handle||'');const uid=esc((accountUser&&accountUser.id)||user?.id||'');const stateHtml=verified?`<div class="account-state account-state-verified"><span class="badge b-green">Verified</span><p class="account-detail">${esc(accountUser.display_name||accountUser.handle||'')}</p><p class="small account-detail-sub">${esc(accountUser.email||'')}</p><p class="small account-detail-sub">Handle: ${handle}</p></div>`:`<div class="account-state account-state-anon"><span class="badge">Anonymous</span><p class="account-detail">${handle}</p><p class="small account-detail-sub">User ID: <code>${uid}</code></p></div>`;const redeemHtml=verified?'':`<div class="account-redeem"><p class="small account-redeem-label">Have an invite code?</p><input id="inviteCode" name="inviteCode" autocomplete="one-time-code" placeholder="Invite code"><input id="inviteEmail" name="email" type="email" autocomplete="email" placeholder="Email"><input id="inviteDisplayName" name="displayName" autocomplete="name" placeholder="Display name (optional)"><button class="primary" data-action="redeemInviteUI">Redeem</button><p class="small account-nocode-note">Don't have a code? HumanX is in private preview. Invite codes are shared directly by members.</p></div>`;return`<div class="account-panel-inner">${stateHtml}${redeemHtml}<button class="account-panel-close" data-action="toggleAccountPanel">Close</button></div>`}
function renderAccountPanel(){const el=document.getElementById('account-panel');if(!el)return;if(!accountPanelOpen){el.hidden=true;el.innerHTML='';return}el.hidden=false;el.innerHTML=accountPanelHtml()}
async function redeemInviteUI(){const code=document.getElementById('inviteCode')?.value.trim()||'';const email=document.getElementById('inviteEmail')?.value.trim()||'';const displayName=document.getElementById('inviteDisplayName')?.value.trim()||'';if(!code||!email){toast('Invite code and email are required.');return}try{const data=await api('/api/auth/invite/redeem',{method:'POST',body:JSON.stringify({code,email,displayName:displayName||undefined})});accountUser=data.user||accountUser;toast('Invite redeemed — account verified.');await loadMe();renderAccountPanel();updateWhoBadge()}catch(e){toast(e.message||'Invite redeem failed.')}}
function setStatus(t,ok,bad=false){document.getElementById('status').textContent=t;const d=document.getElementById('dot');d.className='dot '+(bad?'bad':ok?'live':'')}
async function loadGraphStatus(){try{graphStatus=await api('/api/graph-status')}catch{graphStatus=null}}
function q(){return encodeURIComponent(document.getElementById('search')?.value||'')}
async function loadClaims(doRender=true){try{const f=encodeURIComponent(document.getElementById('filter')?.value||'all');const data=await api(`/api/claims?q=${q()}&status=${f}`);claims=data.claims||[];if(data.warning)setStatus(data.warning,false);if(doRender)render()}catch(e){renderError(e)}}
async function loadEvidenceVault(){const data=await api(`/api/evidence-vault?q=${q()}`);evidenceVault=data.evidence||[]}
async function loadTruths(){const data=await api(`/api/truths?q=${q()}`);truths=data.truths||[]}
async function loadBeliefSnapshots(){await ensureSession();const data=await api('/api/belief-snapshots?limit=30');beliefSnapshots=data.snapshots||[]}
async function loadReviewQueue(){const data=await api('/api/review',{headers:adminHeaders()});reviewQueue={claims:data.claims||[],truths:data.truths||[],review:data.review||[],archived_total:data.archived_total||0,archived_claims:data.archived_claims||0,archived_truths:data.archived_truths||0};return reviewQueue}
async function searchCurrent(){if(mode==='vault')return renderVault();if(mode==='truths')return renderTruths();if(mode==='review')return renderReview();if(mode==='belief')return renderBelief();if(mode==='drift')return renderDrift();if(mode==='home')return renderHome();if(mode==='me')return renderMe();await loadClaims(true)}
function setMode(m){lastModeBeforeStudy='arena';mode=m;if(m!=='export')selected=null;document.body.classList.remove('study-mode');document.body.className=(document.body.className||'').split(' ').filter(c=>!c.startsWith('mode-')).join(' ').trim()+' mode-'+m;document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));const _activeTab=document.getElementById('tab-'+m);if(_activeTab){_activeTab.classList.add('active');try{_activeTab.scrollIntoView({behavior:'smooth',block:'nearest',inline:'center'});}catch(_){}}render()}
function cls(s){if(s==='Proven'||String(s).includes('Supported')||String(s).includes('rising'))return'b-green';if(String(s).includes('Disproven')||String(s).includes('Collapse')||String(s).includes('falling'))return'b-red';if(s==='Plausible')return'b-blue';return'b-yellow'}
function meter(n,v){v=Math.max(0,Math.min(100,Number(v||0)));const tip=/^Evidence/.test(n)?'Evidence score reflects submitted support quality and quantity.':/^Test/.test(n)?'Testability reflects how directly the claim can be checked.':/^Surviv/.test(n)?'Survivability reflects how well the claim holds under pressure.':'';return`<div class="meter" title="${tip}"><span>${n} <b class="meter-val">${v}</b></span><div class="bar"><div class="fill" style="width:${v}%"></div></div></div>`}
function deltaMeter(n,v){const sign=v>0?'+':'';return`<div class="meter"><span>${n} ${sign}${esc(v)}</span><div class="bar"><div class="fill" style="width:${Math.min(100,Math.abs(Number(v||0)))}%"></div></div></div>`}
function graphVal(v){return v===null||v===undefined?'ERR':v}
function graphBox(){const g=graphStatus?.graph||{};const items=[['Claims',g.claims],['Evidence',g.evidence],['Truths',g.truths],['Links',g.evidenceClaimLinks],['Votes',g.claimVotes],];const err=graphStatus&&graphStatus.ok===false?`<p class="small error">Graph schema warning: ${esc(Object.keys(graphStatus.errors||{}).join(', ')||'unknown')}</p>`:'';return`<div class="graph-status">${items.map(([k,v])=>`<span><b>${esc(graphVal(v))}</b><small>${k}</small></span>`).join('')}</div><p class="small graph-global-label">Global graph totals</p>${err}`}
function helperText(){if(mode==='drift')return'<p class="small">Drift shows how your saved belief snapshots change over time — a trail, not a scoreboard.</p><p class="small"><b>Save as Truth</b> — records a statement people repeat as true; it does not mean HumanX has proven it.<br><b>Pressure-test as Claim</b> — turns it into a public, testable statement. Evidence and pressure decide how well it survives, not automatic truth status.</p><p class="small review-first-note">Both actions enter Review before going public.</p><p class="small review-first-note">Full profiles carry 77-statement forensic scores. Quick records are lightweight snapshots.</p>';if(mode==='belief')return'<p class="small">Belief Engine maps how a belief works inside you — source, identity load, inheritance, pressure, and what could change your mind.</p><p class="small review-first-note">It does not diagnose you and does not decide what is true. Your answers start in your browser; sending to HumanX is optional and enters Review before becoming public.</p>';if(mode==='home')return'<p class="small"><b>Beliefs → Truths → Claims → Evidence → RunPack</b></p><p class="small review-first-note">New submissions enter Review before becoming public.</p><p class="small">Pseudonymous. No email required.</p>';if(mode==='vault')return'<p class="small">Reusable sources, records, and evidence items. Each can be attached to multiple claims as support or pressure.</p><p class="small"><b>Study Linked Claim</b> opens the connected claim. <b>Attach to Claim</b> links an item into another claim.</p>';if(mode==='truths')return'<p class="small"><b>Truths</b> are statements that circulate as fact — slogans, doctrines, inherited certainties, widely-repeated beliefs.</p><p class="small review-first-note">HumanX records what is asserted, not whether it is correct. Recording a Truth does not verify it.</p><p class="small"><b>Pressure-test as Claim</b> submits a truth as a public claim for review.</p><p class="small review-first-note">Added truths enter Review before going public.</p>';if(mode==='review'){const at=reviewQueue.archived_total||0;const ac=reviewQueue.archived_claims||0;const atr=reviewQueue.archived_truths||0;const archivedChip=at>0?`<div class="review-ctx-archived"><span class="review-ctx-archived-label">Archived</span><span class="review-ctx-archived-n">${at}</span><span class="review-ctx-archived-detail">${ac&&atr?`claims ${ac} · truths ${atr}`:ac?`claims ${ac}`:atr?`truths ${atr}`:''}</span><span class="review-ctx-archived-note">not in queue</span></div>`:'';return'<p class="small"><b>Pending</b> items are not public. <b>Approve</b> makes an item public. <b>Reject</b> keeps it private.</p><p class="small review-first-note"><b>Archive</b> is only for rejected smoke/test artefacts.</p><p class="small review-first-note">Report count reflects user flags — not proof of wrongdoing.</p>'+archivedChip;}if(mode==='export')return selected?`<p class="small"><b>Active claim</b><br>${esc(cleanClaimLabel(selected.claim))}</p><p class="small">Create the investigation packet → paste into any AI → import the result here. No AI costs — paste into any AI you already use.</p><p class="small review-first-note">Packets do not publish anything.</p>`:'<p class="small">No claim selected.</p><p class="small">Open a claim from the <b>Claims</b> tab → <b>Study</b> it → click <b>Build RunPack</b>. Then return here to copy or download the packet.</p>';if(mode==='submit')return'<p class="small">A claim is a precise, testable public statement. Scores reflect what evidence has been submitted — not an automatic verdict.</p><p class="small review-first-note">New claims enter Review before becoming public.</p>';return'<p class="small">Browse public claims. Open Study to investigate, vote on, and attach evidence to any claim.</p><p class="small review-first-note">Badges: Public · Pending Review · Rejected · Reported · Archived.</p><p class="small review-first-note">Verdicts are pressure-test labels, not automatic truth rulings.</p><p class="small review-first-note">Use the search bar and verdict filter to narrow the list.</p>'}
function render(){if(mode==='home')return renderHome();if(mode==='belief')return renderBelief();if(mode==='drift')return renderDrift();if(mode==='submit')return renderSubmit();if(mode==='vault')return renderVault();if(mode==='truths')return renderTruths();if(mode==='me')return renderMe();if(mode==='review')return renderReview();if(mode==='export')return renderExport();if(mode==='publicProfile')return renderPublicProfile();renderArena()}
function renderHome(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';const g=graphStatus?.graph||{};const sv=v=>v===null||v===undefined?'unknown':String(v);document.getElementById('main').innerHTML=`<div class="cc-layout"><section class="cc-hero"><div class="cc-hero-left"><span class="badge b-blue">invite-only preview</span><h1 class="cc-title">HumanX</h1><p class="cc-subtitle">Map personal belief. Record what gets repeated as fact. Pressure-test public claims with evidence. HumanX organises what people assert — it does not decide what is true.</p><p class="cc-subtitle cc-intro">HumanX is an invite-only space for testing claims, mapping beliefs, and sharing public thinking profiles.</p><p class="cc-access-note small">You can browse and read public claims without an account. Submitting, saving, and public profile controls require an invite. Invite codes are shared directly by members while HumanX is in early access.</p><p class="cc-intro-bridge">Public profiles and claim pages are shareable directly by link.</p><p class="cc-hero-statusline"><span>${esc(user?.handle||'anon')}</span><span class="cc-sep">·</span><span>${esc(live?'Live':(graphStatus!==null?'Demo mode':'connecting…'))}</span><span class="cc-sep">·</span><span>${claims.length>0?claims.length:sv(g.claims)} claims</span><span class="cc-sep">·</span><span>${sv(g.truths)} truths</span><span class="cc-sep">·</span><span>${sv(g.evidence)} evidence</span></p><div class="pipeline-banner"><div class="pipeline-stage"><b>Beliefs</b><span>personal structure</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>Truths</b><span>repeated certainties</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>Claims</b><span>public statements</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>Evidence</b><span>support &amp; challenge</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>RunPack</b><span>export for AI analysis</span></div></div></div><div class="cc-hero-right">${graphBox()}</div></section><section class="cc-section cc-start-here"><h2 class="cc-section-head">Start here</h2><div class="cc-start-strip"><div class="cc-start-step"><span class="cc-start-n">Step 1</span><b>Explore claims</b><span class="cc-start-desc">Browse public claims being tested. See evidence, pressure, and how each holds up.</span><button class="cc-start-btn" data-action="setMode" data-value="arena">Browse Claims →</button></div><div class="cc-start-step"><span class="cc-start-n">Step 2</span><b>Open &amp; investigate</b><span class="cc-start-desc">Go to Claims and click any card to open it in Study mode. Add evidence, vote, apply pressure, and run tests from there.</span><button class="cc-start-btn" data-action="setMode" data-value="arena">Browse Claims →</button></div><div class="cc-start-step"><span class="cc-start-n">Step 3</span><b>Submit a claim</b><span class="cc-start-desc">Have a testable statement? Submit it publicly. Enters Review before going live.</span><button class="cc-start-btn" data-action="setMode" data-value="submit">Submit Claim →</button></div><div class="cc-start-step"><span class="cc-start-n">Step 4</span><b>Build a RunPack</b><span class="cc-start-desc">Export any studied claim as an AI-ready packet. Paste into any AI — no API costs.</span><button class="cc-start-btn" data-action="setMode" data-value="export">RunPack →</button></div></div></section><section class="cc-section"><h2 class="cc-section-head">Actions</h2><div class="cc-card-grid"><button class="cc-card cc-card-primary" data-action="setMode" data-value="arena"><span class="cc-card-icon">⊞</span><b>Browse Claims</b><span class="cc-card-desc">Open, study, vote on, and attach evidence to public claims. Enter Study mode for evidence, pressure, tests, and analysis.</span><span class="cc-card-when">When: reviewing, attacking, or supporting existing claims.</span><span class="cc-card-action">Browse Claims →</span></button><button class="cc-card" data-action="navBeliefEngine"><span class="cc-card-icon">◉</span><b>Belief Engine</b><span class="cc-card-desc">Map how a belief works inside you before turning it into a public claim. It does not diagnose you and does not decide if you are right. It helps separate personal certainty, inherited ideas, identity pressure, and what could change your mind. Your answers start in your browser; sending anything to HumanX is optional and enters Review before becoming public.</span><span class="cc-card-when">When: starting from personal belief before making a public claim.</span><span class="cc-card-action">Open Belief Engine →</span></button><button class="cc-card" data-action="setMode" data-value="submit"><span class="cc-card-icon">✦</span><b>Submit Claim</b><span class="cc-card-desc">Submit one precise, pressure-testable public statement. Pseudonymous. Enters moderation before going live.</span><span class="cc-card-when">When: you have a belief or truth ready to test publicly.</span><span class="cc-card-action">Submit Claim →</span></button><button class="cc-card" data-action="setMode" data-value="drift"><span class="cc-card-icon">〜</span><b>Drift</b><span class="cc-card-desc">View full Belief Engine profiles and quick belief records over time. A trail of what you believed and how it changed — not a scoreboard.</span><span class="cc-card-when">When: comparing beliefs over time or reviewing saved profile snapshots.</span><span class="cc-card-action">View Drift →</span></button><button class="cc-card" data-action="setMode" data-value="vault"><span class="cc-card-icon">◈</span><b>Evidence Vault</b><span class="cc-card-desc">Reusable sources, documents, datasets, and test records. Attach vault items across multiple claims without duplication.</span><span class="cc-card-when">When: browsing reusable evidence or tracing how a source is used across claims.</span><span class="cc-card-action">Evidence Vault →</span></button><button class="cc-card" data-action="setMode" data-value="truths"><span class="cc-card-icon">◇</span><b>Truths</b><span class="cc-card-desc">Statements people repeat as true — slogans, doctrines, inherited certainties. A Truth in HumanX records repeated assertion, not proven fact. HumanX does not decide if a Truth is correct. Convert any truth into a pressure-testable claim.</span><span class="cc-card-when">When: recording a widely repeated belief or promoting a truth to a public claim.</span><span class="cc-card-action">View Truths →</span></button><button class="cc-card" data-action="setMode" data-value="export"><span class="cc-card-icon">⊡</span><b>RunPack</b><span class="cc-card-desc">Generate a structured analysis packet from any claim. Paste into any AI for external analysis. No AI costs — paste into any AI you already use.</span><span class="cc-card-when">When: ready to export a claim for AI analysis after evidence and pressure are attached.</span><span class="cc-card-action">RunPack Export →</span></button></div></section></div>`}
async function renderBelief(){location.href='/apps/humanx-belief-engine/'}
async function renderDrift(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading Drift…</h2></div>';try{await loadBeliefSnapshots()}catch(e){beliefSnapshots=[]}const ordered=[...beliefSnapshots].sort((a,b)=>(a.createdAt||0)-(b.createdAt||0));const profiles=ordered.filter(isFullBeliefProfile);const quick=ordered.filter(s=>!isFullBeliefProfile(s));document.getElementById('main').innerHTML=`<div class="drift-header"><h2>Drift</h2><span class="badge b-blue">${profiles.length} full profile${profiles.length===1?'':'s'} · ${quick.length} quick record${quick.length===1?'':'s'}</span></div><p class="small" style="margin:0 0 12px">Drift tracks how your belief scores move across saved snapshots — a trail, not a ranking. <b>Full profiles</b> capture 77-statement forensic scores from the Belief Engine. <b>Quick records</b> are lightweight snapshots from a single belief map. Both can be promoted to a public Truth or Claim, which enters Review before going live.</p>${profiles.length?renderProfileDrift(profiles):'<div class="panel drift-empty-panel"><div class="drift-empty-type-head"><h3>Full Belief Engine Profiles</h3><span class="badge b-blue">77 statements</span></div><p class="small">No full profile saved yet. Complete the Belief Engine and click <b>Send to HumanX</b> to record one.</p><button class="primary" data-action="navBeliefEngine">Open Belief Engine</button></div>'}${quick.length?`<div class="drift-section-head"><h3>Quick Belief Records</h3><span class="badge">${quick.length} record${quick.length===1?'':'s'}</span><span class="drift-section-note">lightweight snapshots · not full 77-statement profiles</span></div><div class="grid">${quick.map(beliefSnapshotCard).join('')}</div>`:''}${!ordered.length?'<div class="panel"><div class="empty-state"><p>No belief snapshots yet.</p><p class="small">Open the Belief Engine, map a belief, then optionally send a snapshot back to HumanX. Saved snapshots can be promoted to a Truth or public Claim — which enters Review before becoming public.</p><div class="actions" style="margin-top:10px"><button class="primary" data-action="navBeliefEngine">Open Belief Engine</button></div></div></div>':''}`}
function renderProfileDrift(profiles){const first=profiles[0],last=profiles[profiles.length-1];const ds=(last.stabilityScore||0)-(first.stabilityScore||0),doo=(last.opennessScore||0)-(first.opennessScore||0),dp=(last.pressureScore||0)-(first.pressureScore||0),dc=(last.contradictionCount||0)-(first.contradictionCount||0);const verdict=profiles.length<2?'profile baseline':dp>20?'pressure rising':ds>20?'stability rising':doo>20?'openness rising':ds<-20?'stability falling':'mixed / stable profile drift';const comparePanel=profiles.length>1?`<div class="panel drift-compare-panel"><p class="small drift-compare-label">Drift: <b>${esc(first.label||'earliest')}</b> → <b>${esc(last.label||'latest')}</b></p><div class="meters">${deltaMeter('Stability',ds)}${deltaMeter('Openness',doo)}${deltaMeter('Pressure',dp)}${deltaMeter('Contradictions',dc)}</div><p class="small">${driftText(ds,doo,dp,dc)}</p></div>`:'<p class="small drift-baseline-note">One profile saved — add more to measure drift over time.</p>';return`<div class="drift-section-head"><h3>Full Belief Engine Profiles</h3><span class="badge b-yellow">${esc(verdict)}</span></div>${comparePanel}<div class="grid">${profiles.map(beliefSnapshotCard).join('')}</div>`}
function driftText(ds,doo,dp,dc){const bits=[];if(ds>10)bits.push('belief stability increased');if(ds<-10)bits.push('belief stability weakened');if(doo>10)bits.push('openness increased');if(doo<-10)bits.push('openness narrowed');if(dp>10)bits.push('pressure increased');if(dp<-10)bits.push('pressure reduced');if(dc>0)bits.push('more contradictions were detected');if(dc<0)bits.push('fewer contradictions were detected');return bits.length?bits.join('; ')+'.':'No major movement detected yet.'}
function beliefSnapshotMini(s){return`<span class="badge b-yellow">${esc(s.dominantPattern||s.source||'belief')}</span><h3>${esc(s.label||'Belief record')}</h3><p class="small">${esc(new Date(s.createdAt||Date.now()).toLocaleString())}</p><div class="meters">${meter('Stability',s.stabilityScore)}${meter('Open',s.opennessScore)}${meter('Pressure',s.pressureScore)}</div><p class="small">${esc(shortText(s.summary||'',300))}</p>`}
function beliefSnapshotCard(s){const full=isFullBeliefProfile(s);return`<article class="card belief-card ${full?'belief-card-full':'belief-card-quick'}"><div class="belief-card-badges"><span class="badge ${full?'b-blue':'b-yellow'}">${esc(full?'full profile':(s.dominantPattern||s.source||'belief'))}</span>${full?'<span class="badge b-blue">77 statements</span>':''}</div><h3>${esc(s.label||'Belief record')}</h3><p class="small">${esc(new Date(s.createdAt||Date.now()).toLocaleString())}</p><div class="meters">${meter('Stability',s.stabilityScore)}${meter('Open',s.opennessScore)}${meter('Pressure',s.pressureScore)}</div><p class="small">${esc(shortText(s.summary||'',260))}</p><div class="actions"><button data-action="promoteBelief" data-id="${esc(s.id)}" data-value="truth" title="Records this belief as a widely-repeated Truth statement. Enters moderation before going public.">Save as Truth</button><button class="primary" data-action="promoteBelief" data-id="${esc(s.id)}" data-value="claim" title="Creates a public, pressure-testable Claim from this belief. Enters moderation before going public.">Pressure-test as Claim</button></div><p class="small drift-promote-note">→ both actions enter Review before going public</p></article>`}
function n(id){return Number(document.getElementById(id)?.value||0)}function v(id){return document.getElementById(id)?.value||''}
function buildBeliefSnapshot(){return{}}
function classifyBelief(){return'open belief'}
function beliefPreview(){}
async function saveBeliefMirror(){location.href='/apps/humanx-belief-engine/'}
async function promoteBelief(snapshotId,target){try{await ensureSession();const data=await api('/api/belief-promote',{method:'POST',body:JSON.stringify({snapshotId,target})});if(target==='truth'){toast(data.existing?'Truth reinforced — already in Truths.':'Truth promoted to Review. It will appear publicly after approval.');mode='truths';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-truths')?.classList.add('active');await loadGraphStatus();await renderTruths();return}if(data.claimId){toast(data.existing?'Existing claim opened in Study.':'Claim promoted to Review. It will appear publicly after approval.');mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await loadGraphStatus();await loadClaims(false);await selectClaim(data.claimId);return}toast('Belief promoted')}catch(e){toast(e.message||(target==='truth'?'Truth promotion failed.':'Claim promotion failed.'))}}
function renderArena(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';const _fv=(document.getElementById('filter')?.value||'all').trim();const _sv=(document.getElementById('search')?.value||'').trim();const _hasFilter=_fv!=='all'||_sv.length>0;const _filterHint=_hasFilter?`<p class="small arena-filter-hint">Showing: ${_fv!=='all'?`<b>${_fv}</b> verdict`:''} ${_sv?`matching <b>"${_sv}"</b>`:''}. <button class="btn-mini" data-action="clearFilterAndLoadClaims">Show all</button></p>`:'<p class="small arena-filter-hint">Use the search box or verdict filter at the top of the page to narrow results.</p>';document.getElementById('main').innerHTML=`<div class="section-head"><h2>Claims</h2><p class="arena-intro small">Claims are public ideas being tested. Open one to see the evidence, pressure, and truth trail behind it.</p>${_filterHint}<details class="arena-stats-details"><summary class="small arena-stats-summary">Show public network stats</summary>${graphBox()}</details></div><div class="grid">${claims.map(c=>card(c,true)).join('')||'<div class="panel"><div class="empty-state"><p>No claims match this view.</p><p class="small">Claims are public, testable statements with evidence and pressure attached. Use the <b>Submit</b> tab to add one, or adjust the verdict filter above.</p><div class="actions" style="margin-top:8px"><button class="primary" data-action="setMode" data-value="submit">Submit Claim</button><button data-action="clearFilterAndLoadClaims">Show all</button></div></div></div>'}</div>`}
function card(c,actions=false){const votes=`<span title="Believe">▲ ${esc(c.beliefYes||0)}</span><span title="Reject">▼ ${esc(c.beliefNo||0)}</span><span title="Unsure">~ ${esc(c.uncertainty||0)}</span>${c.contradictions?`<span class="claim-pressure-chip" title="Pressure points">⊘ ${esc(c.contradictions)} pressure</span>`:''}`;const metaParts=[c.type,c.handle?'by '+c.handle:''].filter(Boolean).map(esc).join(' · ');return`<article class="card claim-card" data-action="cardSelectClaim" data-id="${esc(c.id)}" tabindex="0" title="Open study view for this claim"><div class="claim-card-head"><span class="badge ${cls(c.status)}">${esc(c.status||'unknown')}</span>${c.category?`<span class="claim-cat">${esc(c.category)}</span>`:''}</div><h3 class="claim-title">${esc(cleanClaimLabel(c.claim))}</h3>${reviewStatusBadge(c)}${metaParts?`<p class="claim-meta small">${metaParts}</p>`:''}<div class="meters">${meter('Evidence',c.evidenceScore)}${meter('Test',c.testability)}${meter('Survive',c.survivability)}</div><div class="claim-votes">${votes}</div>${actions?`<div class="actions"><button class="primary claim-study-btn" data-action="cardSelectClaim" data-id="${esc(c.id)}">Investigate →</button></div>`:''}</article>`}
const CLAIM_TYPE_HINTS={'Physical/Testable':'Factual statements about the physical world — scientific, empirical, or statistical. Best suited for this system.','Historical':'Claims about past events. Specify dates, actors, or documented outcomes where possible.','Religious/Belief':'Matters of faith or personal conviction. Difficult to falsify — evidence scores will reflect that.','Conspiracy':'Allegations of coordinated deception. Requires specific claims about who, what, and when — not just suspicion.','Product Claim':'Marketing or performance assertions about a specific product or service.','Medical/High Risk':'Health-related claims. Will be flagged for high scrutiny. Be specific and cite sources if you have them.'};
const CAT_CHIPS=['Medicine','Science','Politics','History','Religion','Economics','Law','Technology'];
function updateClaimTypeHint(){const t=document.getElementById('cType')?.value||'Physical/Testable';const el=document.getElementById('cTypeHint');if(el)el.textContent=CLAIM_TYPE_HINTS[t]||'';}
function setCatChip(cat){const el=document.getElementById('cCategory');if(el)el.value=cat;document.querySelectorAll('.cat-chip').forEach(b=>b.classList.toggle('cat-chip-active',b.dataset.cat===cat));}
function renderSubmit(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';if(!_bs.step)_bs.step=1;const html=_bs.step===2?renderBuilderStep2():_bs.step===3?renderBuilderStep3():renderBuilderStep1();document.getElementById('main').innerHTML=html;}
function renderBuilderStep1(){return`<div class="claim-builder"><div class="builder-steps"><span class="builder-step builder-step-active">1 · Raw Thought</span><span class="builder-step">2 · Make It Testable</span><span class="builder-step">3 · Final Claim</span></div><h2>Claim Builder</h2><p class="small builder-intro">Submit a testable claim for review. Redeem your invite in ◎ account to associate submissions with your profile. HumanX turns it into a testable public study after review.</p><p class="small submit-trust-note">Scores reflect submitted evidence — not an automatic verdict.</p><p class="small">Write the thought, belief, suspicion, rant, or pattern exactly as it is. HumanX will help sharpen it before Review.</p><div class="builder-guide"><p class="small"><b>What makes a good claim?</b></p><ul class="builder-guide-list"><li><b>Specific &amp; bounded</b> — not "politicians are corrupt" but "MP expenses rose 40% from 2010–2020"</li><li><b>Testable</b> — something evidence or a study could show to be true or false</li><li><b>A claim, not a truth</b> — if it is something people just repeat as fact rather than investigate, it may fit better as a Truth</li></ul></div><div class="hx-form"><label class="small hx-form-field-hint" for="bRaw">Your raw thought</label><textarea id="bRaw" name="bRaw" rows="3" placeholder="e.g. 'The media always lies about vaccines'" oninput="builderLiveFlags()">${esc(_bs.raw)}</textarea><label class="small hx-form-field-hint" for="bWhy">Why do you think this?</label><textarea id="bWhy" name="bWhy" rows="2" placeholder="e.g. 'I saw studies contradicting each other'">${esc(_bs.why)}</textarea><label class="small hx-form-field-hint" for="bScope">Where does this apply? (time period, geography, group)</label><input id="bScope" name="bScope" value="${esc(_bs.scope)}" placeholder="e.g. 'UK 2010–2020' or 'US adults aged 18–35'"><label class="small hx-form-field-hint" for="bFalsifier">What would change your mind?</label><input id="bFalsifier" name="bFalsifier" value="${esc(_bs.falsifier)}" placeholder="e.g. 'A meta-analysis showing no drop'"><p class="small builder-field-note">Tip: a claim without a clear falsifier may be flagged as a personal belief rather than a testable claim.</p><div id="bFlags" class="builder-flags-live"></div><div class="actions"><button class="primary" data-action="builderNext" data-step="1">Make it testable →</button></div><p class="small review-first-note">Start with one clear sentence. You'll add context next, and the claim will be reviewed before it appears publicly.</p></div></div>`;}
function renderBuilderStep2(){const route=claimBuilderRoute(_bs.flags);const routeNote=route==='truth'?'<p class="builder-route builder-route-truth"><span class="badge b-yellow">looks like a Truth</span> This reads more like a belief, value, or widely-repeated assertion. You can sharpen it into a testable claim below — or save the original assertion as a Truth for Review now.</p><p class="small builder-truth-vs-claim">Truths are stronger conclusions. Claims are ideas still being tested. If unsure, submit as a claim.</p><div class="builder-route-actions"><button class="primary" data-action="submitBuilderTruth">Save as Truth for Review</button></div>':'<p class="builder-route builder-route-claim"><span class="badge b-green">looks testable</span> This has the shape of a falsifiable claim. Sharpen the wording and continue.</p>';return`<div class="claim-builder"><div class="builder-steps"><span class="builder-step">1 · Raw Thought</span><span class="builder-step builder-step-active">2 · Make It Testable</span><span class="builder-step">3 · Final Claim</span></div><h2>Make It Testable</h2><div class="builder-original"><p class="small builder-original-label">Original text</p><blockquote class="builder-original-text">${esc(_bs.raw)}</blockquote></div>${renderBuilderFlags(_bs.flags)}${routeNote}<div class="hx-form"><label class="small hx-form-field-hint" for="bDraft">Draft claim <span class="small">(edit freely)</span></label><textarea id="bDraft" name="bDraft" rows="2" placeholder="One precise, testable statement">${esc(_bs.draft)}</textarea><label class="small hx-form-field-hint" for="bScope2">Scope / context</label><input id="bScope2" name="bScope2" value="${esc(_bs.scope)}" placeholder="Time period, geography, or group"><label class="small hx-form-field-hint" for="bFalsifier2">Falsifier / what would change your mind</label><input id="bFalsifier2" name="bFalsifier2" value="${esc(_bs.falsifier)}" placeholder="What evidence would prove this wrong?"><label class="small hx-form-field-hint" for="bCategory">Category</label><div class="cat-chips">${CAT_CHIPS.map(c=>`<button type="button" class="cat-chip${_bs.category===c?' cat-chip-active':''}" data-cat="${c}" data-action="builderSetCat">${c}</button>`).join('')}</div><input id="bCategory" name="bCategory" value="${esc(_bs.category)}" placeholder="Or type a category"><p class="small builder-field-note">Category helps moderators and searchers find your claim. Pick the closest chip or type your own.</p><label class="small hx-form-field-hint" for="bType">Claim type</label><select id="bType" name="bType" onchange="builderSetType(this.value)">${['Physical/Testable','Historical','Religious/Belief','Conspiracy','Product Claim','Medical/High Risk'].map(t=>`<option${_bs.type===t?' selected':''}>${t}</option>`).join('')}</select><p class="small hx-form-field-hint">${esc(CLAIM_TYPE_HINTS[_bs.type]||'')}</p><div class="actions"><button data-action="builderBack">← Back</button><button class="primary" data-action="builderNext" data-step="2">Continue to final claim →</button></div><p class="small review-first-note">Not submitted yet.</p></div></div>`;}
function renderBuilderStep3(){const route=claimBuilderRoute(_bs.flags);const isTruth=route==='truth';const decisionBadge=isTruth?'<span class="badge b-yellow">Truth route</span> <span class="badge b-blue">Claim route available</span>':'<span class="badge b-yellow">Submit as Claim for Review</span>';const decisionNote=isTruth?'<p class="small builder-truth-note">Truth route records the original assertion for Review. It does not verify it as fact. You can also submit the cleaned claim instead.</p>':'<p class="small review-first-note">Enters admin Review before going public. Not visible until approved.</p>';const actionBtns=isTruth?'<button data-action="builderBack">← Back</button><button class="primary" data-action="submitBuilderTruth">Save as Truth for Review</button><button data-action="submitBuilderClaim">Submit Claim for Review</button>':'<button data-action="builderBack">← Back</button><button class="primary" data-action="submitBuilderClaim">Submit Claim for Review</button>';return`<div class="claim-builder"><div class="builder-steps"><span class="builder-step">1 · Raw Thought</span><span class="builder-step">2 · Make It Testable</span><span class="builder-step builder-step-active">3 · Final Claim</span></div><h2>Final Claim</h2><div class="builder-summary"><div class="builder-summary-row"><span class="builder-summary-label">CLAIM</span><span class="builder-summary-val">${esc(_bs.draft)}</span></div><div class="builder-summary-row"><span class="builder-summary-label">ORIGINAL</span><span class="builder-summary-val builder-summary-muted">${esc(_bs.raw)}</span></div><div class="builder-summary-row"><span class="builder-summary-label">WHY</span><span class="builder-summary-val builder-summary-muted">${esc(_bs.why||'—')}</span></div><div class="builder-summary-row"><span class="builder-summary-label">SCOPE</span><span class="builder-summary-val builder-summary-muted">${esc(_bs.scope||'—')}</span></div><div class="builder-summary-row"><span class="builder-summary-label">FALSIFIER</span><span class="builder-summary-val builder-summary-muted">${esc(_bs.falsifier||'—')}</span></div><div class="builder-summary-row"><span class="builder-summary-label">FLAGS</span><span class="builder-summary-val">${renderBuilderFlags(_bs.flags)||'<span class=\\"small\\">none</span>'}</span></div><div class="builder-summary-row"><span class="builder-summary-label">DECISION</span><span class="builder-summary-val">${decisionBadge}</span></div></div>${decisionNote}<div class="builder-what-next"><p class="small"><b>What happens next:</b> your submission enters admin Review and is not visible publicly until approved. Once approved it becomes a live public claim — others can add evidence, vote on it, and pressure-test it. You will be taken directly to Study your claim straight after submitting.</p></div><div class="actions">${actionBtns}${accountUser&&accountUser.verified?'':'<p class="small review-first-note" style="margin-top:6px">Submitting as a guest — <button class="btn-mini" data-action="toggleAccountPanel">Redeem invite →</button> to track this with your profile.</p>'}</div></div>`;}
function claimBuilderFlags(text,scope,falsifier){const flags=[];const t=String(text||'').trim();if(!t||t.length<5)return flags;const lo=t.toLowerCase();if(t.length<20)flags.push({code:'too_short',msg:'Very short — add a specific quantity, date, or outcome.',route:null});if(/^(i think|i believe|i feel|in my opinion|personally)/i.test(lo))flags.push({code:'personal_belief',msg:'Personal framing — reframe as an observable, falsifiable statement.',route:'truth'});if(/^(people are|everyone is|nobody is|all [a-z]+ are)/i.test(lo)&&t.length<60)flags.push({code:'too_broad',msg:'Broad scope — narrow to a specific group, time, or place.',route:null});if(/\b(should|must|ought|need to)\b/i.test(lo)&&!/\b(study|evidence|data|show|prove|found)\b/i.test(lo))flags.push({code:'normative_value',msg:'Normative framing — says what should be rather than what is.',route:'truth'});if(/\b(always|never|all|none|every one|no one)\b/i.test(lo)&&t.length<80)flags.push({code:'too_vague',msg:'Absolute language — hard to test. Add a time range or specific context.',route:null});if(/\b(evil|corrupt|immoral|disgusting|terrible)\b/i.test(lo))flags.push({code:'emotional_rant',msg:'Evaluative language — state the observable act or outcome instead.',route:'truth'});if(/\b(they|the government|the media|big pharma|the elite)\b.*\b(hiding|control|want|plan|secret)\b/i.test(lo))flags.push({code:'conspiracy',msg:'Hidden-actor framing — name the specific actor, act, and evidence.',route:'claim'});if(/\b(will|going to|predict|forecast|by 20\d\d)\b/i.test(lo))flags.push({code:'prediction',msg:'Prediction — future claims score low until evidence arrives.',route:'claim'});if(/\bcauses?\b/i.test(lo)&&!/\b(study|evidence|found|shows|documented|paper)\b/i.test(lo))flags.push({code:'causal',msg:'Causal claim — link to a study or documented mechanism.',route:'claim'});if(falsifier&&String(falsifier).trim().length>5)flags.push({code:'testable_enough',msg:'Falsifier provided — good signal this is testable.',route:'claim'});else flags.push({code:'no_falsifier',msg:'No falsifier yet — what evidence would change your mind?',route:null});return flags;}
function claimBuilderRoute(flags){const truth=(flags||[]).filter(f=>f.route==='truth').length;const claim=(flags||[]).filter(f=>f.route==='claim').length;return(truth>claim&&truth>0)?'truth':'claim';}
function claimBuilderDraft(raw,scope){let t=String(raw||'').trim().replace(/\s+/g,' ');t=t.replace(/^(i think[,]?\s*|i believe[,]?\s*|i feel[,]?\s*|in my opinion[,]?\s*|personally[,]?\s*)/i,'');t=t.charAt(0).toUpperCase()+t.slice(1);if(!t.match(/[.!?]$/))t=t+'.';if(scope&&scope.trim()&&!t.toLowerCase().includes(scope.trim().toLowerCase()))t=t.replace(/[.!?]$/,' — '+scope.trim()+'.');return t.trim();}
function renderBuilderFlags(flags){if(!flags||!flags.length)return'';const clr={too_short:'b-yellow',personal_belief:'b-yellow',too_broad:'b-yellow',normative_value:'b-yellow',too_vague:'b-yellow',emotional_rant:'b-red',conspiracy:'b-blue',prediction:'b-blue',causal:'b-blue',testable_enough:'b-green',no_falsifier:'b-yellow'};return`<div class="builder-flags">${flags.map(f=>`<span class="badge builder-flag ${clr[f.code]||'b-yellow'}">${esc(f.msg)}</span>`).join('')}</div>`;}
function builderLiveFlags(){const raw=(document.getElementById('bRaw')?.value||'').trim();const scope=document.getElementById('bScope')?.value||'';const falsifier=document.getElementById('bFalsifier')?.value||'';const flags=claimBuilderFlags(raw,scope,falsifier);const el=document.getElementById('bFlags');if(el)el.innerHTML=flags.length?renderBuilderFlags(flags):'';}
function builderSetCat(c){_bs.category=c;const el=document.getElementById('bCategory');if(el)el.value=c;document.querySelectorAll('.cat-chip').forEach(b=>b.classList.toggle('cat-chip-active',b.dataset.cat===c));}
function builderSetType(v){_bs.type=v;}
function builderNext(step){if(step===1){const raw=(document.getElementById('bRaw')?.value||'').trim();if(raw.length<5){toast('Add your raw thought before continuing.');return;}_bs.raw=raw;_bs.why=document.getElementById('bWhy')?.value||'';_bs.scope=document.getElementById('bScope')?.value||'';_bs.falsifier=document.getElementById('bFalsifier')?.value||'';_bs.flags=claimBuilderFlags(_bs.raw,_bs.scope,_bs.falsifier);if(!_bs.draft)_bs.draft=claimBuilderDraft(_bs.raw,_bs.scope);_bs.step=2;renderSubmit();}else if(step===2){const draft=(document.getElementById('bDraft')?.value||'').trim();if(draft.length<5){toast('Write a draft claim before continuing.');return;}_bs.draft=draft;_bs.scope=document.getElementById('bScope2')?.value||_bs.scope;_bs.falsifier=document.getElementById('bFalsifier2')?.value||_bs.falsifier;_bs.category=document.getElementById('bCategory')?.value||_bs.category;_bs.type=document.getElementById('bType')?.value||_bs.type;_bs.flags=claimBuilderFlags(_bs.raw,_bs.scope,_bs.falsifier);_bs.step=3;renderSubmit();}}
function builderBack(){if(_bs.step>1){_bs.step--;renderSubmit();}}
function builderPayload(){const route=claimBuilderRoute(_bs.flags);return{route,rawText:_bs.raw||'',why:_bs.why||'',scope:_bs.scope||'',falsifier:_bs.falsifier||'',draftClaim:_bs.draft||'',finalClaim:_bs.draft||'',category:_bs.category||'',claimType:_bs.type||'',systemFlags:(_bs.flags||[]).map(f=>f.code||f)};}
async function submitBuilderClaim(){if(!_bs.draft||_bs.draft.trim().length<5){toast('Go back to Step 2 and write a draft claim first.');return;}const flagSummary=_bs.flags.filter(f=>f.code!=='testable_enough'&&f.code!=='no_falsifier').map(f=>f.code).join(', ');const context=['Claim Builder context:','Original user text: '+_bs.raw,_bs.why?'Why user thinks this: '+_bs.why:'',_bs.scope?'Scope: '+_bs.scope:'',_bs.falsifier?'Pressure/falsifier: '+_bs.falsifier:'',flagSummary?'System flags: '+flagSummary:''].filter(Boolean).join('\n');const body={claim:_bs.draft.trim(),category:_bs.category||'general',type:_bs.type||'Physical/Testable',initialEvidence:context,claim_builder:builderPayload()};try{const data=await api('/api/claims',{method:'POST',body:JSON.stringify(body)});selected=data.claim;_bs={step:1,raw:'',why:'',scope:'',falsifier:'',draft:'',category:'',type:'Physical/Testable',flags:[]};await loadGraphStatus();await loadClaims(false);if(data.existing){toast('This claim already exists.');document.getElementById('main').innerHTML=`<div class="panel form-panel"><span class="badge b-blue">already exists</span><h2>Claim already exists</h2><p class="small">A claim with the same meaning is already in the system.</p><p class="small"><b>${esc(cleanClaimLabel(selected.claim))}</b></p><div class="actions"><button class="primary" onclick="selectClaim('${esc(selected.id)}')">Study existing claim</button><button data-action="setMode" data-value="submit">Build another claim</button><button data-action="setMode" data-value="arena">Browse Claims</button></div></div>`;}else{toast('Claim submitted for Review. It will appear publicly after approval.');document.getElementById('main').innerHTML=`<div class="panel form-panel"><span class="badge b-yellow">in review</span><h2>Claim submitted for Review</h2><p class="small">Your claim is now in the moderation queue and is not yet public. It will appear publicly after an admin approves it. Usually within a few days.</p><p class="small"><b>${esc(cleanClaimLabel(selected.claim))}</b></p><div class="actions"><button class="primary" onclick="selectClaim('${esc(selected.id)}')">Study this claim</button><button data-action="setMode" data-value="submit">Build another claim</button><button data-action="setMode" data-value="arena">Browse Claims</button></div></div>`;}}catch(e){const _em=e.message||'';toast(_em==='RATE_LIMITED'?'Too many submissions. Try again in about an hour.':_em==='CLAIM_TOO_SHORT'?'Claim is too short. Add a little more detail before submitting.':_em||'Claim submission failed.');}}
async function submitBuilderTruth(){const statement=(_bs.raw||'').trim();if(!statement||statement.length<5){toast('Go back to Step 1 and enter your original thought first.');return;}const route=claimBuilderRoute(_bs.flags);const body={statement,category:_bs.category||'general',origin:'Claim Builder raw thought',truthType:route==='truth'?'personal-belief':'common',confidenceLabel:'claimed',claim_builder:builderPayload()};try{await api('/api/truths',{method:'POST',body:JSON.stringify(body)});_bs={step:1,raw:'',why:'',scope:'',falsifier:'',draft:'',category:'',type:'Physical/Testable',flags:[]};await loadGraphStatus();await renderTruths();toast('Saved as Truth for Review. It will appear publicly after approval.');}catch(e){const _em=e.message||'';toast(_em==='TRUTH_TOO_SHORT'?'Truth statement is too short. Add a little more detail before submitting.':_em==='RATE_LIMITED'?'Too many submissions. Try again in about an hour.':_em||'Truth submission failed.');}}
function groupEvidenceByCllaim(items){const groups=new Map();for(const e of items){const key=e.claimId||e.claim_id||null;if(!groups.has(key))groups.set(key,{claimId:key,claim:e.claim||null,items:[]});groups.get(key).items.push(e);}return[...groups.values()].sort((a,b)=>{if(!a.claimId&&b.claimId)return 1;if(a.claimId&&!b.claimId)return -1;return(a.claim||'').localeCompare(b.claim||'');});}
function vaultGroupsHtml(items){if(!items.length)return'';const groups=groupEvidenceByCllaim(items);return groups.map(g=>{const sup=g.items.filter(e=>(e.stance||'support')==='support').length;const prs=g.items.filter(e=>{const s=e.stance||'support';return s==='pressure'||s==='attack';}).length;const counts=[sup>0?`${sup} support`:'',prs>0?`${prs} pressure`:''].filter(Boolean).join(' · ');const title=g.claim?cleanClaimLabel(g.claim):'Unlinked evidence';const isUnlinked=!g.claimId;return`<div class="vault-group${isUnlinked?' vault-group-unlinked':''}"><div class="vault-group-head"><span class="vault-group-title">${esc(title)}</span><div class="vault-group-meta"><span class="badge b-blue">${g.items.length} item${g.items.length===1?'':'s'}</span>${counts?`<span class="vault-group-counts">${esc(counts)}</span>`:''} ${g.claimId?`<button class="btn-link-small" onclick="studyFromVault('${esc(g.claimId)}')">Study claim ↗</button>`:''}</div></div><div class="vault-group-grid">${g.items.map(evidenceCard).join('')}</div></div>`;}).join('');}
async function renderVault(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading Evidence…</h2></div>';try{await loadEvidenceVault();document.getElementById('casefile').innerHTML=helperText();const count=evidenceVault.length;document.getElementById('main').innerHTML=`<div id="attach-modal" class="attach-modal" style="display:none"></div><div class="vault-header"><div class="vault-header-top"><h2>Evidence Vault</h2><span class="badge b-blue">${count} item${count===1?'':'s'}</span></div><p class="small">Reusable sources, documents, data, and records. Each item can be attached to multiple claims as support or as a pressure attack. Evidence records reflect what has been submitted — not an automatic verdict on the claim.</p>${graphBox()}</div><div class="vault-groups">${vaultGroupsHtml(evidenceVault)||'<div class="empty-state"><p>No evidence records yet.</p><p class="small">Open a claim from the <b>Claims</b> tab, enter Study mode, and use the side panel to add a source or pressure attack. Items saved there appear here and can be reused across multiple claims.</p><div class="actions" style="margin-top:8px"><button class="primary" data-action="setMode" data-value="arena">Browse Claims</button></div></div>'}</div>`}catch(e){renderError(e)}}
function evidenceCard(e){const a=parseAnalysis(e.body);const stance=e.linked_stance||e.stance||'support';const isPressure=stance==='pressure'||stance==='attack';const stanceClr=isPressure?'b-red':stance==='support'?'b-green':'b-yellow';const stanceMod=isPressure?'evidence-card-pressure':stance==='support'?'evidence-card-support':'evidence-card-neutral';const quality=e.quality||'unknown';const qualClr=quality==='repeatable'||quality==='documented'||quality==='media'?'b-blue':quality==='vibes'?'':'b-yellow';const mediaType=e.media_type||e.mediaType||'text';const reliability=e.reliability_score||e.reliabilityScore||null;const date=e.updated_at||e.updatedAt||e.created_at||e.createdAt||null;const dateStr=date?new Date(date).toLocaleDateString():null;const reuse=e.reuse_count||e.reuseCount||null;const claimBlock=e.claim?`<div class="vault-card-claim"><span class="pill">linked claim</span><span class="small">${esc(cleanClaimLabel(e.claim))}</span><span class="badge ${cls(e.claimStatus)}">${esc(e.claimStatus||'unknown')}</span></div>`:'';return`<article class="card evidence-card ${stanceMod}"><div class="vault-card-head"><b class="vault-card-title">${esc(e.title)}</b><div class="vault-card-badges"><span class="badge ${stanceClr}">${esc(stance)}</span><span class="badge ${qualClr}">${a?'analysis':esc(quality)}</span><span class="badge">${esc(mediaType)}</span>${reliability?`<span class="pill">reliability ${esc(reliability)}</span>`:''} ${reuse&&reuse>1?`<span class="pill">↻ reused ${esc(reuse)}×</span>`:''}</div></div>${a?analysisSummary(a):evidenceBodyHtml(e.body||e.note||'',240)}${sourceLink(e.sourceUrl||e.source_url)}${claimBlock}${dateStr?`<p class="small vault-card-date">Updated ${esc(dateStr)}</p>`:''}<div class="actions">${(e.claimId||e.claim_id)?`<button onclick="studyFromVault('${esc(e.claimId||e.claim_id)}')" title="Open the linked claim in Study mode">Study Linked Claim</button>`:''}<button class="primary" onclick="attachEvidencePrompt('${esc(e.id)}')" title="Attach this item to a different claim as support or pressure">Attach to Claim</button></div></article>`}
function analysisSummary(a){return`<div class="analysis-card"><span class="badge ${cls(a.verdict)}">${esc(a.verdict||'analysis')}</span><div class="meters">${meter('Evidence',a.evidence_score||a.evidenceScore||0)}${meter('Test',a.testability||0)}${meter('Survive',a.survivability||0)}</div><p class="small">${esc(a.plain_language_summary||a.plainLanguageSummary||'Legacy analysis result stored in evidence. New results should be saved in Analysis.')}</p></div>`}
async function renderTruths(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading Truths…</h2></div>';try{await loadTruths();const _isAdm=!!adminToken();const _artCnt=(truths||[]).filter(isTruthArtifact).length;const _brdCnt=(truths||[]).filter(t=>isTruthBorderlineArtefact(t)&&!isTruthArtifact(t)).length;const _perCnt=(truths||[]).filter(isTruthPersonalBelief).length;document.getElementById('casefile').innerHTML=helperText();document.getElementById('main').innerHTML=`<div class="section-head"><h2>Truths</h2><span class="badge b-yellow">widely asserted · not auto-verified</span>${graphBox()}</div><p class="small" style="margin:0 0 10px">Statements that circulate as fact — slogans, doctrines, inherited certainties, repeated beliefs. <b>Public means visible, not proven.</b> Recording a truth here does not verify it. Use <b>Pressure-test as Claim</b> to submit one for evidence-based review.</p><p class="small review-first-note"><b>Truth vs Claim:</b> a Truth records a widely-repeated assertion as-is — HumanX does not verify it. A Claim is a public, testable version that can be challenged with evidence and pressure. Use <b>Pressure-test as Claim</b> on any Truth card to convert it into an investigable Claim.</p><details class="truth-add-details"><summary class="truth-add-summary">Add a public Truth</summary><div class="panel compact-form hx-form"><h3 class="hx-form-head">Add a Truth</h3><p class="small builder-field-note">Record it as people say it — not a refined testable claim. Include where it comes from and what category it belongs to. HumanX stores the assertion, not a verdict on whether it is correct.</p><input id="truthStatement" name="truthStatement" placeholder="Repeated statement or widely-asserted belief"><input id="truthCategory" name="truthCategory" placeholder="Category (e.g. Health, Religion, Politics)"><input id="truthOrigin" name="truthOrigin" placeholder="Origin (e.g. family, media, scripture, science)"><label class="small hx-form-field-hint" for="truthType">Truth type</label><select id="truthType" name="truthType"><option value="common">Common truth</option><option value="religious">Religious truth</option><option value="political">Political truth</option><option value="scientific">Scientific consensus</option><option value="family">Family truth</option><option value="cultural">Cultural truth</option></select><button class="primary" data-action="submitTruth">Submit Truth for Review</button><p class="small review-first-note">Enters Review before going public.</p></div></details>${_isAdm?renderTruthAdminBar(_artCnt,_brdCnt,_perCnt):''}${_isAdm?renderTruthFilterBar(truths):''}<div id="truth-grid-container" class="grid truth-grid">${applyTruthAdminFilter(truths).map(t=>truthCard(t)).join('')||'<div class="panel"><div class="empty-state"><p>No truths match this view.</p><p class="small">Open <b>Add a public Truth</b> above to record a widely-repeated statement — a slogan, doctrine, or inherited certainty. HumanX stores the assertion; it does not verify whether it is correct.</p></div></div>'}</div>`}catch(e){renderError(e)}}
function isTruthPersonalBelief(t){return t.truthType==='personal-belief'||String(t.origin||'').toLowerCase().includes('belief snapshot')||/belief engine profile/i.test(t.statement||'');}
function isTruthArtifact(t){const s=String(t.statement||'').trim();if(s.length<4)return true;if(/^(statement|slogan|truth|claim|placeholder|test|demo|example|sample|label|title)$/i.test(s))return true;const letters=s.replace(/[^a-z]/gi,'').toLowerCase();if(letters.length>6){const vowels=(letters.match(/[aeiou]/g)||[]).length;if(vowels/letters.length<0.12)return true;}if(/^(.{2,5})\1{2,}$/i.test(s.replace(/[\s-]/g,'')))return true;return false;}
function isTruthBorderlineArtefact(t){if(isTruthArtifact(t))return false;const s=String(t.statement||'').trim();if(s.length<2)return false;const words=s.split(/\s+/);if(words.length>=2&&words.length<=5&&s.length<=40&&s===s.toUpperCase()&&/[A-Z]/.test(s))return true;const alpha=(s.match(/[a-zA-Z]/g)||[]).length;if(s.replace(/\s/g,'').length>4&&alpha/s.replace(/\s/g,'').length<0.5)return true;return false;}
function applyTruthAdminFilter(list){const f=truthAdminFilter||'all';if(f==='artefacts')return list.filter(isTruthArtifact);if(f==='borderline')return list.filter(t=>isTruthBorderlineArtefact(t)&&!isTruthArtifact(t));if(f==='personal')return list.filter(isTruthPersonalBelief);if(f==='clean')return list.filter(t=>!isTruthArtifact(t)&&!isTruthBorderlineArtefact(t)&&!isTruthPersonalBelief(t));return list;}
function renderTruthAdminBar(artefactCount,borderlineCount,personalCount){return`<div class="truth-admin-bar" style="grid-column:1/-1"><span>⚙</span> <b>Admin Truth tools</b> — <span class="truth-admin-stat">${artefactCount} artefact${artefactCount===1?'':'s'}</span> · <span class="truth-admin-stat">${borderlineCount} borderline</span> · <span class="truth-admin-stat">${personalCount} personal belief</span><span class="truth-admin-bar-hint">Artefacts: archive button active. Borderline: advisory badge only. Personal: policy deferred.</span></div>`;}
function renderTruthFilterBar(list){const counts={all:list.length,artefacts:list.filter(isTruthArtifact).length,borderline:list.filter(t=>isTruthBorderlineArtefact(t)&&!isTruthArtifact(t)).length,personal:list.filter(isTruthPersonalBelief).length,clean:list.filter(t=>!isTruthArtifact(t)&&!isTruthBorderlineArtefact(t)&&!isTruthPersonalBelief(t)).length};const defs=[['all','All'],['artefacts','Artefacts'],['borderline','Borderline'],['personal','Personal'],['clean','Clean']];const chips=defs.map(([f,label])=>{const n=counts[f];const active=truthAdminFilter===f;return`<button class="truth-filter-chip${active?' truth-filter-chip-active':''}" data-action="setTruthAdminFilter" data-value="${f}">${label}${n>0?` <span class="truth-filter-count">${n}</span>`:''}</button>`}).join('');return`<div id="truth-filter-bar" class="truth-filter-bar" style="grid-column:1/-1">${chips}</div>`;}
async function setTruthAdminFilter(f){truthAdminFilter=f||'all';await renderTruths();}
function copyTruthId(id){navigator.clipboard.writeText(id).then(()=>toast('Truth ID copied')).catch(()=>toast('Copy failed — select the ID manually'));}
async function archiveTruthArtefact(id){if(!adminToken()){toast('Admin token required');return;}const truth=(truths||[]).find(t=>t.id===id);const statement=truth?truth.statement:id;if(!confirm('Archive this Truth artefact?\n\n"'+statement+'"\nID: '+id+'\n\nThis will reject then archive it.'))return;try{await api('/api/review/decision',{method:'POST',headers:adminHeaders(),body:JSON.stringify({targetType:'truth',targetId:id,decision:'rejected'})});await api('/api/review/cleanup',{method:'POST',headers:adminHeaders(),body:JSON.stringify({target_type:'truth',target_id:id,junk_override:true,reason:'Admin UI artefact cleanup'})});toast('Truth artefact archived');await renderTruths()}catch(e){toast(e.message||'Archive failed')}}
// D-137C: derive the state of a truth's pressure-test claim (if any) so the card
// can show a state-specific badge and button instead of a generic "claim derived"
// chip + always-fresh-looking submit button. truths.linked_claim_id always points
// to the single canonical derived claim (see src/truths.js listTruths comment).
const TRUTH_CLAIM_STATE_BADGES={public:['CLAIM PUBLIC','b-green'],review:['CLAIM IN REVIEW','b-yellow'],rejected:['CLAIM REJECTED','b-red'],archived:['CLAIM ARCHIVED','b-muted'],duplicate:['CLAIM DUPLICATE','b-purple']};
function truthClaimStateMeta(t){const claimId=t.linkedClaimId||t.linked_claim_id||null;if(!claimId)return{state:null,badgeHtml:'',btnClass:'primary',btnLabel:'Pressure-test as Claim →',btnAction:`convertTruth('${esc(t.id)}')`,note:'Creates a claim for review — does not prove this truth.'};const state=t.linkedClaimReviewState||t.linked_claim_review_state||'review';const[label,cls]=TRUTH_CLAIM_STATE_BADGES[state]||['CLAIM '+state.toUpperCase(),'b-muted'];const badgeHtml=`<span class="badge ${cls} truth-claim-state-badge">${esc(label)}</span>`;if(state==='public')return{state,badgeHtml,btnClass:'primary',btnLabel:'Open Claim Study →',btnAction:`openTruthClaimStudy('${esc(claimId)}')`,note:'Opens the existing public claim — this truth itself remains unaffected.'};if(state==='review')return{state,badgeHtml,btnClass:'truth-claim-btn-muted',btnLabel:'Already in Review',btnAction:`convertTruth('${esc(t.id)}')`,note:'This truth remains public. The derived pressure-test claim is already in review — clicking does not create a new submission.'};const labelByState={rejected:'Rejected pressure-test',archived:'Archived pressure-test',duplicate:'Duplicate pressure-test'};const btnLabel=labelByState[state]||('Pressure-test '+state);return{state,badgeHtml,btnClass:'truth-claim-btn-muted',btnLabel,btnAction:`convertTruth('${esc(t.id)}')`,note:`This truth remains public. Only the derived pressure-test claim is ${state} — clicking does not create a new submission.`};}
async function openTruthClaimStudy(claimId){lastModeBeforeStudy='truths';mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await selectClaim(claimId)}
function truthCard(t){const metaParts=[t.category||'general',t.origin&&t.origin!=='unknown'?'origin: '+t.origin:null,'by '+(t.handle||'anon')].filter(Boolean).map(esc).join(' · ');const pressureStat=(t.pressureScore||0)>0?`<span class="truth-stat truth-stat-pressure" title="Pressure score">⊘ ${esc(t.pressureScore)} pressure</span>`:'';const personalBelief=isTruthPersonalBelief(t);const artifact=isTruthArtifact(t);const isAdmin=!!adminToken();const borderline=isAdmin&&isTruthBorderlineArtefact(t)&&!artifact;const idSuffix=t.id?t.id.slice(-8):'';const claimMeta=truthClaimStateMeta(t);return`<article class="card truth-card${artifact?' truth-card-artifact':''}"><div class="truth-card-head"><span class="badge b-yellow">${esc(t.truthType||'truth')}</span><span class="badge b-muted truth-not-verified">not verified</span>${personalBelief?`<span class="badge b-muted truth-personal-badge">personal belief</span>`:''} ${artifact?`<span class="badge b-muted truth-artifact-badge">? artefact</span>`:''} ${borderline?`<span class="badge b-muted truth-borderline-badge">? borderline</span>`:''} ${t.confidenceLabel?`<span class="badge">${esc(t.confidenceLabel)}</span>`:''} ${claimMeta.badgeHtml}</div><h3 class="truth-title">${esc(cleanClaimLabel(t.statement))}</h3>${reviewStatusBadge(t,false,true)}<p class="small truth-meta">${metaParts}</p><div class="truth-stats"><span class="truth-stat" title="Reinforcement count">↻ ${esc(t.repetitionScore||1)} repeated</span>${pressureStat}</div>${t.id?(isAdmin?`<p class="small truth-id-line truth-id-admin"><code class="truth-id-full" title="${esc(t.id)}">${esc(t.id)}</code><button class="btn-mini btn-copy-id" data-action="copyTruthId" data-id="${esc(t.id)}" title="Copy full truth ID">copy id</button></p>`:`<p class="small truth-id-line">id: …${esc(idSuffix)}</p>`):''}${isAdmin&&artifact?`<p class="small truth-admin-actions"><button class="btn-mini btn-archive-artifact" data-action="archiveTruthArtefact" data-id="${esc(t.id)}" title="Reject and archive this artefact">archive artefact</button></p>`:''}<div class="actions"><button class="${claimMeta.btnClass}" onclick="${claimMeta.btnAction}" title="${esc(claimMeta.note)}">${esc(claimMeta.btnLabel)}</button></div><p class="small truth-convert-note">${esc(claimMeta.note)}</p></article>`}

// D-137D/E: My HumanX personal dashboard frontend.
// Reads-only against GET /api/my-humanx, which is always scoped to the
// requester's own x-humanx-user identity (D-137B). No share buttons, no
// public profile, no target-user parameter — this page only ever shows
// the current browser's own content.
const ME_STATE_LABELS={public:'Public',review:'Review',rejected:'Rejected',archived:'Archived',duplicate:'Duplicate'};
const ME_STATE_CLR={public:'b-green',review:'b-yellow',rejected:'b-red',archived:'b-muted',duplicate:'b-purple'};
const ME_VISIBLE_CAP=5;
const ME_FILTER_STATES=['all','public','review','rejected','archived','duplicate'];
let meData=null;
let meStateFilter='all';
let meExpanded={};
async function openMyClaimStudy(claimId){lastModeBeforeStudy='me';mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await selectClaim(claimId)}
function meRerender(){if(meData)document.getElementById('main').innerHTML=renderMeHtml(meData)}
function meSetFilter(state){meStateFilter=ME_FILTER_STATES.includes(state)?state:'all';meRerender()}
function meToggleExpand(key){meExpanded[key]=!meExpanded[key];meRerender()}
function meFilterRows(rows){if(meStateFilter==='all')return rows||[];return(rows||[]).filter(r=>(r.review_state||'review')===meStateFilter)}
function meVisibleSlice(key,rows){return meExpanded[key]?rows:rows.slice(0,ME_VISIBLE_CAP)}
function meShowAllControl(key,total){if(total<=ME_VISIBLE_CAP)return'';const exp=!!meExpanded[key];return`<button class="btn-mini me-toggle" data-action="meToggleExpand" data-key="${key}">${exp?'Show less':'Show all ('+total+')'}</button>`}
function meFilterBarHtml(){return`<div class="me-filter-bar">${ME_FILTER_STATES.map(s=>`<button class="me-filter-btn ${meStateFilter===s?'active':''}" data-action="meSetFilter" data-value="${s}">${s==='all'?'All':esc(ME_STATE_LABELS[s]||s)}</button>`).join('')}</div>`}
function meAccountCardHtml(u){if(!u)return'<div class="panel"><p class="small">Account info unavailable.</p></div>';const verified=!!u.verified;return`<div class="panel me-account-card"><div class="me-account-head"><span class="badge ${verified?'b-green':'b-muted'}">${verified?'Verified':'Anonymous'}</span></div><p class="me-account-name">${esc(u.display_name||u.handle||'')}</p>${verified&&u.email?`<p class="small me-account-sub">${esc(u.email)}</p>`:''}<p class="small me-account-sub">Handle: ${esc(u.handle||'')}</p><p class="small me-account-sub">User ID: <code>${esc(u.id||'')}</code></p><div class="me-account-actions"><button class="btn-mini" data-action="exportMyHumanXData">Export my data (JSON)</button><p class="small builder-field-note" style="margin-top:5px">Downloads a JSON file of your claims, truths, evidence, snapshots, and profile — a local copy for your own records, not shared with anyone.</p></div></div>`}
async function exportMyHumanXData(){try{await ensureSession();const data=await api('/api/my-humanx/export');const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=`humanx-export-${(data.user&&data.user.id)||'me'}.json`;document.body.appendChild(a);a.click();a.remove();URL.revokeObjectURL(url);toast('Export downloaded.')}catch(e){toast(e.message||'Export failed.')}}
// D-140B: Profile Settings panel — foundation only. Saving here does not make
// anything public yet; there is no public read route or public page in this
// patch (see docs/D140A audit). The Copy share link button only ever reflects
// the last *saved* state, never the unsaved form values.
// D-141B: 1-2 sample public items for the owner-side preview, drawn only from
// already-loaded /api/my-humanx data (meData) — no new backend call. Claims/
// truths only, filtered to review_state==='public' (which also excludes
// archived-by-user rows, since archiving flips review_state to 'archived').
function meProfilePublicSamples(){const claims=(meData?.claims||[]).filter(c=>(c.review_state||'review')==='public').slice(0,2).map(c=>({type:'Claim',text:shortText(cleanClaimLabel(c.claim||''),80)}));const truths=(meData?.truths||[]).filter(t=>(t.review_state||'review')==='public').slice(0,2).map(t=>({type:'Truth',text:shortText(cleanClaimLabel(t.statement||''),80)}));return[...claims,...truths].slice(0,2)}
function meProfilePreviewSampleHtml(samples){if(!samples||!samples.length)return'';return`<div class="pp-item-list">${samples.map(s=>`<div class="pp-item-row"><span class="small me-item-meta">${esc(s.type)}</span><span class="me-item-text">${esc(s.text)}</span></div>`).join('')}</div>`}
// D-142B: computes the exact public-safe snapshot summary client-side from
// already-loaded meData.belief_snapshots — same narrow field set the backend
// returns via GET /api/u/:slug's sharedSnapshot, so the owner preview matches
// reality. Never reads dimensions_json, raw_json, stress_points_json, or
// full contradictions_json text.
// D-209B: Summary now mirrors the actual public API response shape exactly.
// Only Class-1 fields (label, contradictionCount, createdAt) are included.
// dominantPattern, topAlignmentName, and score fields are excluded so the
// owner preview card cannot show data the public card no longer exposes.
function meSharedSnapshotSummary(){const rows=meData?.belief_snapshots||[];const shared=rows.find(s=>!!s.public_summary_enabled);if(!shared)return null;let vis=null;try{if(shared.visibility_json)vis=JSON.parse(shared.visibility_json);}catch{}return{id:shared.id,label:shared.label||null,contradictionCount:shared.contradiction_count||0,createdAt:shared.created_at||null,scoresEnabled:vis?.scores===true,stabilityScore:shared.stability_score??0,opennessScore:shared.openness_score??0,pressureScore:shared.pressure_score??0}}
// D-209B: Card mirrors renderPublicProfileSnapshotHtml exactly —
// label, contradictionCount, createdAt, and guardrail copy only.
// Identity fields and score meters are not rendered here; see D-209A.
// D-209H: s.scores is a nested object {stabilityScore,opennessScore,pressureScore}
// present only when visibility_json.scores===true (or preview checkbox checked).
function meSharedSnapshotCardHtml(s){if(!s)return'';const created=s.createdAt?new Date(s.createdAt).toLocaleDateString():null;const scoresHtml=s.scores?`<div class="pp-snapshot-scores"><p class="small pp-snapshot-scores-label">Reflection scores</p><p class="small pp-disclaimer">Scores are reflection signals, not intelligence, morality, or truth rankings.</p><p class="small">${esc(s.scores.stabilityScore??0)} stability · ${esc(s.scores.opennessScore??0)} openness · ${esc(s.scores.pressureScore??0)} pressure</p></div>`:'';return`<div class="pp-card pp-snapshot-card"><h3>Shared Belief Snapshot</h3><p class="small pp-disclaimer">A snapshot you chose to share — pattern observations from your own self-submitted answers, not a diagnosis or personality test. One snapshot, shared by choice — not your complete profile.</p><p class="small pp-disclaimer">Belief patterns describe how you interact with claims. They are not a score of intelligence, morality, or truth. Belief identity details are private by default.</p>${s.label?`<p class="pp-snapshot-label">${esc(s.label)}</p>`:''}<p class="small">${esc(s.contradictionCount)} tension${s.contradictionCount===1?'':'s'} noted</p>${created?`<p class="small pp-snapshot-date">Snapshot recorded ${esc(created)}</p>`:''}${scoresHtml}</div>`}
// D-142C: shows a compact preview of the selected snapshot, or a clear
// "nothing will appear" message — and frames sharing as optional and
// separate from the profile_public toggle, since the owner could enable
// one without the other.
// D-209B: Intro copy updated to state explicitly what sharing does and does not expose.
// D-209H: includes live-preview div + optional public fields (scores-only toggle).
// Checkbox onchange fires meBeliefVisibilityPreviewUpdate() — local only, no backend call.
// "Save public belief visibility" button fires saveBeliefVisibilityUI() — backend call.
function meSharedSnapshotPreviewBlockHtml(){const intro='<p class="small">Belief snapshot sharing is optional and separate from your public profile toggle. Shared snapshots show your label, tension count, and date. Reflection scores can optionally be shown if you save that choice below. Belief alignment details, pattern labels, and reflection cards remain private.</p>';const s=meSharedSnapshotSummary();if(!s)return`${intro}<p class="small pp-empty">No belief snapshot will appear publicly.</p>`;const previewScores=s.scoresEnabled?{stabilityScore:s.stabilityScore,opennessScore:s.opennessScore,pressureScore:s.pressureScore}:null;const visibilityBlock=`<div class="me-belief-visibility-block"><h4 class="me-belief-visibility-title">Optional public fields</h4><label class="me-belief-visibility-row small"><input type="checkbox" id="meBeliefVisibilityScores" ${s.scoresEnabled?'checked':''} onchange="meBeliefVisibilityPreviewUpdate()"> Show reflection scores on public profile</label><p class="small me-belief-visibility-warn">Scores are reflection signals, not intelligence, morality, or truth rankings.</p><p class="small">Only the fields you save here will appear publicly. You can hide them again later.</p><div class="me-belief-visibility-actions"><button class="btn-mini" data-action="saveBeliefVisibilityUI">Save public belief visibility</button></div></div>`;return`${intro}<p class="small me-mirror-guardrail">Preview — this is exactly what others will see: <em class="me-belief-preview-note">Preview updates before saving. Public profile changes only after Save.</em></p><div id="meBeliefVisibilityPreviewCard">${meSharedSnapshotCardHtml({...s,scores:previewScores})}</div>${visibilityBlock}`}
// D-209H: updates the snapshot preview card on checkbox change without saving.
function meBeliefVisibilityPreviewUpdate(){const scoresChecked=!!document.getElementById('meBeliefVisibilityScores')?.checked;const s=meSharedSnapshotSummary();if(!s)return;const el=document.getElementById('meBeliefVisibilityPreviewCard');if(el)el.innerHTML=meSharedSnapshotCardHtml({...s,scores:scoresChecked?{stabilityScore:s.stabilityScore,opennessScore:s.opennessScore,pressureScore:s.pressureScore}:null})}
async function saveBeliefVisibilityUI(){const s=meSharedSnapshotSummary();if(!s||!s.id){toast('No shared snapshot selected.');return;}const scoresEnabled=!!document.getElementById('meBeliefVisibilityScores')?.checked;try{await ensureSession();await api(`/api/belief-snapshots/${encodeURIComponent(s.id)}/visibility`,{method:'POST',body:JSON.stringify({scores:scoresEnabled})});toast(scoresEnabled?'Reflection scores are now public on your shared snapshot.':'Reflection scores hidden from your public snapshot.');await renderMe()}catch(e){toast(e.message||'Could not save belief visibility.')}}
function meProfilePreviewBodyHtml(slug,bio,isPublic,counts,samples){if(!isPublic)return'<p class="small pp-empty">Profile is off — nothing public yet.</p>';const c=counts||{};const countsHtml=`<span class="badge">Claims ${esc(c.claims?.public||0)}</span><span class="badge">Truths ${esc(c.truths?.public||0)}</span><span class="badge">Evidence ${esc(c.evidence?.public||0)}</span><span class="badge">Pressure ${esc(c.pressure?.public||0)}</span>`;return`<p class="me-profile-preview-slug">/u/${esc(slug||'your-slug')}</p>${bio?`<p class="small">${esc(shortText(bio,240))}</p>`:''}<div class="me-mirror-chip-row">${countsHtml}</div><p class="small pp-counts-note">Counts reflect public, non-archived activity only.</p>${meSharedSnapshotPreviewBlockHtml()}${meProfilePreviewSampleHtml(samples)}`}
function meUpdateProfilePreview(){const slug=(document.getElementById('meProfileSlugInput')?.value||'').trim();const bio=(document.getElementById('meProfileBioInput')?.value||'').trim();const isPublic=!!document.getElementById('meProfilePublicToggle')?.checked;const body=document.getElementById('meProfilePreviewBody');if(body)body.innerHTML=meProfilePreviewBodyHtml(slug,bio,isPublic,meData?.counts,meProfilePublicSamples());const copyBtn=document.getElementById('meProfileCopyBtn');if(copyBtn){const canCopy=isPublic&&!!slug;copyBtn.disabled=!canCopy;copyBtn.style.display=canCopy?'':'none'}}
async function saveProfileSettingsUI(){const isPublic=!!document.getElementById('meProfilePublicToggle')?.checked;const slug=(document.getElementById('meProfileSlugInput')?.value||'').trim();const bio=(document.getElementById('meProfileBioInput')?.value||'').trim();try{await ensureSession();await api('/api/my-humanx/profile-settings',{method:'POST',body:JSON.stringify({profile_public:isPublic,profile_slug:slug,profile_bio:bio})});toast('Profile settings saved.');await renderMe()}catch(e){toast(e.message||'Could not save profile settings.')}}
// D-143B: shares the real /u/:slug path (server-rendered OG meta tags) now
// that the Worker serves it — the #/u/:slug hash route still works as a
// fallback for any in-app link that doesn't go through this function.
function meCopyProfileLink(){const isPublic=!!document.getElementById('meProfilePublicToggle')?.checked;const slug=(document.getElementById('meProfileSlugInput')?.value||'').trim();if(!isPublic||!slug)return;const link=`${location.origin}/u/${encodeURIComponent(slug)}`;if(navigator.clipboard?.writeText){navigator.clipboard.writeText(link).then(()=>toast('Profile link copied.')).catch(()=>toast('Copy failed — select the link manually.'))}else{toast('Copy failed — select the link manually.')}}
function meProfileSettingsHtml(data){const u=data.user||{};const isPublic=!!u.profile_public;const slug=u.profile_slug||'';const bio=u.profile_bio||'';const canCopy=isPublic&&!!slug;const guestNote=accountUser&&accountUser.verified?'':'<p class="small review-first-note" style="margin-bottom:8px">Verify your account with an invite code before enabling a public profile. Use ◎ account in the header to redeem your invite.</p>';return`<div class="panel me-profile-settings"><h3>Profile Settings</h3>${guestNote}<p class="small me-mirror-guardrail">Off by default. Nothing about your account is public until you turn this on and save. Your public profile shows your bio, an optional belief snapshot, and claims you have made public — all other activity stays private.</p><label class="me-profile-toggle"><input type="checkbox" id="meProfilePublicToggle" ${isPublic?'checked':''} onchange="meUpdateProfilePreview()"> Make my profile public</label><label class="small" for="meProfileSlugInput">Profile link slug</label><input id="meProfileSlugInput" type="text" value="${esc(slug)}" placeholder="your-slug" oninput="meUpdateProfilePreview()"><label class="small" for="meProfileBioInput">Bio</label><textarea id="meProfileBioInput" maxlength="240" oninput="meUpdateProfilePreview()">${esc(bio)}</textarea><div class="me-profile-preview"><p class="small">This is what others would see if you publish.</p><div id="meProfilePreviewBody">${meProfilePreviewBodyHtml(slug,bio,isPublic,data.counts,meProfilePublicSamples())}</div></div><div class="me-profile-actions"><button class="primary btn-mini" data-action="saveProfileSettingsUI">Save</button><button class="btn-mini" id="meProfileCopyBtn" data-action="meCopyProfileLink" ${canCopy?'':'disabled'} style="${canCopy?'':'display:none'}">Copy share link</button></div></div>`}
// D-140C: public, no-auth, read-only profile view rendered from the #/u/:slug
// hash route. No edit/archive/export controls, no owner-only Me data — this
// renders strictly from the GET /api/u/:slug response.
async function openPublicProfileClaimStudy(claimId){lastModeBeforeStudy='arena';mode='arena';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-arena')?.classList.add('active');await selectClaim(claimId)}
function ppToggleShowMore(btn){const moreDiv=btn.previousElementSibling.querySelector('.pp-more-items');if(!moreDiv)return;const showing=moreDiv.style.display!=='none';moreDiv.style.display=showing?'none':'';btn.setAttribute('aria-expanded',showing?'false':'true');const count=parseInt(btn.dataset.more,10);btn.textContent=showing?`Show ${count} more`:'Show less'}
function renderPublicProfileClaimsHtml(rows){if(!rows||!rows.length)return'<p class="small pp-empty">No public claims yet.</p>';return`<div class="pp-item-list">${rows.map(c=>`<div class="pp-item-row"><span class="me-item-text">${esc(shortText(cleanClaimLabel(c.claim||''),140))}</span><span class="small me-item-meta">${esc(c.category||'')}</span><button class="btn-mini" data-action="openPublicProfileClaimStudy" data-id="${esc(c.id)}">View in HumanX →</button><button class="btn-mini" data-action="copyClaimLink" data-id="${esc(c.id)}">Copy link</button></div>`).join('')}</div>`}
function renderPublicProfileTruthsHtml(rows){if(!rows||!rows.length)return'';return`<div class="pp-item-list">${rows.map(t=>`<div class="pp-item-row"><span class="me-item-text">${esc(shortText(cleanClaimLabel(t.statement||''),140))}</span><span class="small me-item-meta">${esc(t.category||'')}</span></div>`).join('')}</div>`}
function renderPublicProfileEvidenceHtml(rows){if(!rows||!rows.length)return'';const BATCH=5;const first=rows.slice(0,BATCH);const rest=rows.slice(BATCH);const rowHtml=e=>`<div class="pp-item-row"><span class="me-item-text">${esc(shortText(e.title||'Evidence',140))}</span><span class="small me-item-meta">${esc(evidenceQualityLabel(e.quality||''))}</span></div>`;const restHtml=rest.length?`<div class="pp-more-items" id="pp-more-ev" style="display:none">${rest.map(rowHtml).join('')}</div>`:'';const toggleBtn=rest.length?`<button class="btn-pp-show-more" data-action="ppToggleShowMore" data-more="${rest.length}" aria-expanded="false" aria-controls="pp-more-ev">Show ${rest.length} more</button>`:'';return`<div class="pp-item-list">${first.map(rowHtml).join('')}${restHtml}</div>${toggleBtn}`}
function pressureSeverityLabel(s){const n=Number(s)||1;return n<=1?'low pressure':n===2?'moderate pressure':n===3?'notable pressure':n===4?'high pressure':'critical pressure'}
function renderPublicProfilePressureHtml(rows){if(!rows||!rows.length)return'';const BATCH=5;const first=rows.slice(0,BATCH);const rest=rows.slice(BATCH);const rowHtml=p=>`<div class="pp-item-row"><span class="me-item-text">${esc(shortText(p.title||'Pressure point',140))}</span><span class="small me-item-meta">${esc(pressureSeverityLabel(p.severity))}</span></div>`;const restHtml=rest.length?`<div class="pp-more-items" id="pp-more-pr" style="display:none">${rest.map(rowHtml).join('')}</div>`:'';const toggleBtn=rest.length?`<button class="btn-pp-show-more" data-action="ppToggleShowMore" data-more="${rest.length}" aria-expanded="false" aria-controls="pp-more-pr">Show ${rest.length} more</button>`:'';return`<div class="pp-item-list">${first.map(rowHtml).join('')}${restHtml}</div>${toggleBtn}`}
// D-142B: optional shared-snapshot card, rendered only when the API returned
// one (i.e. the owner explicitly selected a snapshot AND the profile is
// public). Third-person wording since this describes someone else's choice
// to a visitor — mirrors meSharedSnapshotCardHtml's owner-facing copy but
// is intentionally a separate function/string, not shared, so the two
// audiences' wording can be reviewed and changed independently.
// D-209H: renders s.scores block if present — set by backend only when
// visibility_json.scores===true. No scores shown unless owner opted in.
function renderPublicProfileSnapshotHtml(s){if(!s)return'';const created=s.createdAt?new Date(s.createdAt).toLocaleDateString():null;const scoresHtml=s.scores?`<div class="pp-snapshot-scores"><p class="small pp-snapshot-scores-label">Reflection scores</p><p class="small pp-disclaimer">Scores are reflection signals, not intelligence, morality, or truth rankings.</p><p class="small">${esc(s.scores.stabilityScore??0)} stability · ${esc(s.scores.opennessScore??0)} openness · ${esc(s.scores.pressureScore??0)} pressure</p></div>`:'';return`<div class="panel pp-card pp-snapshot-card"><h3>Shared Belief Snapshot</h3><p class="small pp-disclaimer">A snapshot this person chose to share — pattern observations from their own self-submitted answers, not a diagnosis or personality test. One snapshot, shared by choice — not their complete profile.</p><p class="small pp-disclaimer">Belief patterns describe how someone interacts with claims. They are not a score of intelligence, morality, or truth. Belief identity details are private by default.</p>${s.label?`<p class="pp-snapshot-label">${esc(s.label)}</p>`:''}<p class="small">${esc(s.contradictionCount)} tension${s.contradictionCount===1?'':'s'} noted</p>${created?`<p class="small pp-snapshot-date">Shared snapshot recorded ${esc(created)}</p>`:''}${scoresHtml}</div>`}
function copyPublicProfileLink(btn,slug){const url=`${location.origin}/u/${encodeURIComponent(slug||'')}`;btn.textContent='Copied!';btn.disabled=true;const reset=()=>{btn.textContent='Copy profile link';btn.disabled=false};if(navigator.clipboard){navigator.clipboard.writeText(url).then(()=>setTimeout(reset,1500)).catch(()=>reset());}else{try{const t=document.createElement('textarea');t.value=url;document.body.appendChild(t);t.select();document.execCommand('copy');document.body.removeChild(t);}catch(e){}setTimeout(reset,1500)}}
function copyClaimLink(btn,id){const url=`${location.origin}/c/${encodeURIComponent(id||'')}`;btn.textContent='Copied!';btn.disabled=true;const reset=()=>{btn.textContent='Copy link';btn.disabled=false};if(navigator.clipboard){navigator.clipboard.writeText(url).then(()=>setTimeout(reset,1500)).catch(()=>reset());}else{try{const t=document.createElement('textarea');t.value=url;document.body.appendChild(t);t.select();document.execCommand('copy');document.body.removeChild(t);}catch(e){}setTimeout(reset,1500)}}
function renderPublicProfileHtml(p){const counts=p.counts||{};const isOwner=!!(meData&&meData.user&&meData.user.profile_slug&&meData.user.profile_slug===p.slug);const backLabel=isOwner?'← Back to Me':'← Back to Home';const sn=p.sharedSnapshot;const bioFallback='';const contextBlock=`<div class="panel pp-card pp-context-block"><p class="small">HumanX is a public thinking profile: a place where claims, beliefs, and tested truths are collected over time. This page shows what this person has chosen to share publicly.</p><p class="small pp-vocab-line"><strong>Claims being tested</strong> are assertions this person is tracking. <strong>Public truths</strong> are widely-held statements — collected, not endorsed. <strong>Evidence quality</strong> rates how well a source holds up to scrutiny. <strong>Questions under pressure</strong> are challenges raised against a claim.</p><p class="small pp-disclaimer">Public profile shows selected public HumanX activity only. It is not a truth ruling or personality diagnosis.</p></div>`;const truthsHtml=renderPublicProfileTruthsHtml(p.recentTruths);const evidenceHtml=renderPublicProfileEvidenceHtml(p.recentEvidence);const pressureHtml=renderPublicProfilePressureHtml(p.recentPressure);const countsCard=`<div class="panel pp-card pp-counts-card"><h3>Public Activity</h3><div class="me-mirror-chip-row"><span class="badge">Claims ${esc(counts.claims||0)}</span><span class="badge">Truths ${esc(counts.truths||0)}</span><span class="badge">Evidence ${esc(counts.evidence||0)}</span><span class="badge">Pressure ${esc(counts.pressure||0)}</span></div><p class="small pp-counts-note">Counts reflect public, non-archived activity only.</p></div>`;return`<div class="section-head"><h2>Public Profile</h2></div><div class="panel pp-header pp-card"><p class="pp-display-name">${esc(p.displayName||'anon')}</p><p class="small pp-slug">/u/${esc(p.slug||'')}</p>${p.bio?`<p class="small pp-bio">${esc(p.bio)}</p>`:bioFallback}</div>${renderPublicProfileSnapshotHtml(sn)}${contextBlock}<div class="panel pp-section"><h3>Claims being tested</h3>${renderPublicProfileClaimsHtml(p.recentClaims)}</div>${truthsHtml?`<div class="panel pp-section"><h3>Public truths</h3>${truthsHtml}</div>`:''}${countsCard}${evidenceHtml?`<div class="panel pp-section"><h3>Supporting evidence</h3>${evidenceHtml}</div>`:''}${pressureHtml?`<div class="panel pp-section"><h3>Questions under pressure</h3>${pressureHtml}</div>`:''}<div class="actions pp-footer-actions" style="margin-top:10px"><button class="primary" data-action="setMode" data-value="${isOwner?'me':'home'}">${backLabel}</button>${!isOwner?`<button class="btn-secondary" data-action="copyPublicProfileLink" data-slug="${esc(p.slug||'')}">Copy profile link</button>`:''}<button data-action="setMode" data-value="arena">Browse all claims →</button></div>`}
async function renderPublicProfile(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML='';document.getElementById('side-tools').style.display='none';document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('main').innerHTML='<div class="panel"><h2>Loading profile…</h2></div>';try{const data=await api(`/api/u/${encodeURIComponent(publicProfileSlug||'')}`);document.getElementById('main').innerHTML=renderPublicProfileHtml(data.profile||{})}catch(e){document.getElementById('main').innerHTML=`<div class="panel"><h3>Profile not found or not public.</h3><div class="actions" style="margin-top:10px"><button class="primary" data-action="setMode" data-value="home">← Back to Home</button></div></div>`}}
function meArchiveErrorMessage(code){if(code==='STILL_REFERENCED')return'Cannot archive — this is still used by another public claim.';if(code==='PROTECTED')return'This item is protected and cannot be archived.';if(code==='NOT_FOUND_OR_NOT_OWNED')return'Item not found or not owned by you.';return code||'Archive failed.'}
function meFindItemLabel(targetType,targetId){if(!meData)return targetId;const list=targetType==='claim'?meData.claims:targetType==='truth'?meData.truths:targetType==='evidence'?meData.evidence:targetType==='pressure'?meData.pressure:[];const item=(list||[]).find(x=>x.id===targetId);if(!item)return targetId;if(targetType==='claim')return shortText(cleanClaimLabel(item.claim||''),80);if(targetType==='truth')return shortText(cleanClaimLabel(item.statement||''),80);return shortText(item.title||'',80)}
function meArchiveItemUI(targetType,targetId){const label=meFindItemLabel(targetType,targetId);hxModal({title:'Archive item',body:`<p class="small" style="margin:0 0 8px">Archive <strong>${esc(label)}</strong>? It will be hidden from My HumanX and public listings. This does not delete it — no hard delete in My HumanX yet.</p>`,confirmLabel:'Archive',cancelLabel:'Cancel',onConfirm:async(close)=>{close();try{await ensureSession();await api('/api/my-humanx/archive',{method:'POST',body:JSON.stringify({targetType,targetId})});toast('Archived.');await renderMe()}catch(e){toast(meArchiveErrorMessage(e.message))}}})}
function meCountsRow(label,counts){if(!counts)return'';const chips=Object.keys(ME_STATE_LABELS).map(s=>`<span class="badge ${ME_STATE_CLR[s]} me-count-chip">${esc(ME_STATE_LABELS[s])}: ${esc(counts[s]||0)}</span>`).join('');return`<div class="me-count-row"><span class="me-count-label">${esc(label)}</span><div class="me-count-chips">${chips}</div></div>`}
function meRecentClaimsHtml(rows){if(!rows||!rows.length)return'<p class="small me-empty">No claims match this filter.</p>';return`<div class="me-item-list">${rows.map(c=>{const state=c.review_state||'review';const isPublic=state==='public';const isArchived=state==='archived';const label=ME_STATE_LABELS[state]||state;const clr=ME_STATE_CLR[state]||'b-muted';const when=reviewAge(c.updated_at||c.created_at);return`<div class="me-item-row"><span class="badge ${clr}">${esc(label)}</span><span class="me-item-text">${esc(shortText(cleanClaimLabel(c.claim||''),140))}</span><span class="small me-item-meta">${esc(when)}</span>${isPublic?`<button class="btn-mini" data-action="openMyClaimStudy" data-id="${esc(c.id)}">Open Study →</button><button class="btn-mini" data-action="copyClaimLink" data-id="${esc(c.id)}">Copy link</button>`:''}${!isArchived?`<button class="btn-mini danger" data-action="meArchiveItem" data-item-type="claim" data-id="${esc(c.id)}">Archive</button>`:''}</div>`}).join('')}</div>`}
function meRecentTruthsHtml(rows){if(!rows||!rows.length)return'<p class="small me-empty">No truths match this filter.</p>';return`<div class="me-item-list">${rows.map(t=>{const state=t.review_state||'review';const isPublic=state==='public';const isArchived=state==='archived';const label=ME_STATE_LABELS[state]||state;const clr=ME_STATE_CLR[state]||'b-muted';const when=reviewAge(t.updated_at||t.created_at);return`<div class="me-item-row"><span class="badge ${clr}">${esc(label)}</span><span class="me-item-text">${esc(shortText(cleanClaimLabel(t.statement||''),140))}</span><span class="small me-item-meta">${esc(when)}</span>${isPublic?`<button class="btn-mini" data-action="setMode" data-value="truths">View in Truths →</button>`:''}${!isArchived?`<button class="btn-mini danger" data-action="meArchiveItem" data-item-type="truth" data-id="${esc(t.id)}">Archive</button>`:''}</div>`}).join('')}</div>`}
function meRecentEvidenceHtml(rows){if(!rows||!rows.length)return'<p class="small me-empty">No evidence matches this filter.</p>';return`<div class="me-item-list">${rows.map(e=>{const state=e.review_state||'public';const isArchived=state==='archived';const label=ME_STATE_LABELS[state]||state;const clr=ME_STATE_CLR[state]||'b-muted';const when=reviewAge(e.created_at);const type=e.type||'evidence';return`<div class="me-item-row"><span class="badge ${clr}">${esc(label)}</span><span class="me-item-text">${esc(shortText(e.title||'Evidence',140))}</span><span class="small me-item-meta">${esc(type)} · ${esc(when)}</span>${e.claim_id?`<code class="me-item-parent" title="Parent claim — not opened automatically, may not be public">claim: ${esc(e.claim_id)}</code>`:''}${!isArchived?`<button class="btn-mini danger" data-action="meArchiveItem" data-item-type="evidence" data-id="${esc(e.id)}">Archive</button>`:''}</div>`}).join('')}</div>`}
function meRecentPressureHtml(rows){if(!rows||!rows.length)return'<p class="small me-empty">No pressure points match this filter.</p>';return`<div class="me-item-list">${rows.map(p=>{const state=p.review_state||'public';const isArchived=state==='archived';const label=ME_STATE_LABELS[state]||state;const clr=ME_STATE_CLR[state]||'b-muted';const when=reviewAge(p.updated_at||p.created_at);return`<div class="me-item-row"><span class="badge ${clr}">${esc(label)}</span><span class="me-item-text">${esc(shortText(p.title||'Pressure point',140))}</span><span class="small me-item-meta">${esc(when)}</span>${p.claim_id?`<code class="me-item-parent" title="Parent claim — not opened automatically, may not be public">claim: ${esc(p.claim_id)}</code>`:''}${!isArchived?`<button class="btn-mini danger" data-action="meArchiveItem" data-item-type="pressure" data-id="${esc(p.id)}">Archive</button>`:''}</div>`}).join('')}</div>`}
// D-142B: snapshot sharing is opt-in, per-snapshot, and exclusive — selecting
// one clears any other (enforced server-side too, see saveProfileSettings()).
// This radio group never touches profile_public/slug/bio; it always reuses
// the currently-saved values from meData.user so a sharing change can't
// accidentally publish (or unpublish) the rest of the profile.
async function meShareSnapshotUI(snapshotId){const u=meData?.user||{};try{await ensureSession();await api('/api/my-humanx/profile-settings',{method:'POST',body:JSON.stringify({profile_public:!!u.profile_public,profile_slug:u.profile_slug||'',profile_bio:u.profile_bio||'',shared_snapshot_id:snapshotId})});toast(snapshotId?'Snapshot shared on your public profile.':'Sharing cleared — no snapshot is shared.');await renderMe()}catch(e){toast(e.message||'Could not update snapshot sharing.')}}
function meBeliefSnapshotsHtml(rows){if(!rows||!rows.length)return'<p class="small me-empty">No belief snapshots yet.</p>';const anyShared=rows.some(s=>!!s.public_summary_enabled);const helper='<p class="small me-snapshot-helper">Choose one snapshot to show on your public profile. You can also share none.</p>';const rowsHtml=rows.map(s=>{const isShared=!!s.public_summary_enabled;return`<div class="me-item-row${isShared?' me-item-row-selected':''}"><span class="me-item-text">${esc(s.label||'Snapshot')}</span><span class="small me-item-meta">stability ${esc(s.stability_score??0)} · openness ${esc(s.openness_score??0)} · pressure ${esc(s.pressure_score??0)} · ${esc(reviewAge(s.created_at))}</span><label class="me-snapshot-share small"><input type="radio" name="meSharedSnapshot" ${isShared?'checked':''} data-action="meShareSnapshotUI" data-id="${esc(s.id)}"> Share on public profile</label></div>`}).join('');const noneRow=`<div class="me-item-row me-snapshot-share-none${!anyShared?' me-item-row-selected':''}"><label class="me-snapshot-share small"><input type="radio" name="meSharedSnapshot" ${!anyShared?'checked':''} data-action="meShareSnapshotUI" data-id=""> Do not share a snapshot</label></div>`;return`${helper}<div class="me-item-list">${rowsHtml}${noneRow}</div>`}
// D-139B: Belief Mirror panel — entirely client-side synthesis of already-stored
// data from GET /api/my-humanx. No AI/LLM call, no new endpoint. Every card is
// framed as a tentative pattern observation, never a diagnosis or verdict —
// see docs/D139A audit wording guardrails.
function meSafeParseJson(raw,fallback){if(raw==null)return fallback;if(typeof raw==='object')return raw;try{const v=JSON.parse(raw);return v==null?fallback:v}catch{return fallback}}
function meMirrorGuardrailHtml(){return'<p class="small me-mirror-guardrail">Pattern observations from your own answers and submissions — not a diagnosis or personality test. Private belief reflections are for self-study. They are not personality labels or truth rankings.</p>'}
function meMirrorLatestCardHtml(latest){if(!latest)return'';return`<div class="me-mirror-card"><h4>Latest snapshot</h4><p class="me-mirror-pattern">${esc(latest.dominant_pattern||'Pattern not labeled')}</p>${meter('Stability',latest.stability_score)}${meter('Openness',latest.openness_score)}${meter('Pressure',latest.pressure_score)}</div>`}
function meMirrorDriftCardHtml(latest,previous){if(!latest||!previous)return'';const d=(a,b)=>{const v=(Number(a)||0)-(Number(b)||0);return(v>0?'+':'')+v};return`<div class="me-mirror-card"><h4>Recent drift</h4><p class="small">Since your last check-in:</p><p class="me-mirror-drift-row">Stability <b>${esc(d(latest.stability_score,previous.stability_score))}</b></p><p class="me-mirror-drift-row">Openness <b>${esc(d(latest.openness_score,previous.openness_score))}</b></p><p class="me-mirror-drift-row">Pressure <b>${esc(d(latest.pressure_score,previous.pressure_score))}</b></p></div>`}
function meMirrorTopCategories(claims,truths){const counts={};const add=v=>{const c=String(v||'').trim();if(!c)return;counts[c]=(counts[c]||0)+1};(claims||[]).forEach(c=>add(c.category));(truths||[]).forEach(t=>add(t.category));return Object.entries(counts).sort((a,b)=>b[1]-a[1]).slice(0,3)}
function meMirrorCategoriesCardHtml(claims,truths){const top=meMirrorTopCategories(claims,truths);if(!top.length)return'';return`<div class="me-mirror-card"><h4>Recurring categories</h4><div class="me-mirror-chip-row">${top.map(([cat,n])=>`<span class="badge b-blue">${esc(cat)} · ${esc(n)}</span>`).join('')}</div></div>`}
function meMirrorBalanceCardHtml(pressure,evidence){const sevCounts={};(pressure||[]).forEach(p=>{const s=Number(p.severity)||0;if(s>0)sevCounts[s]=(sevCounts[s]||0)+1});const qualCounts={};(evidence||[]).forEach(e=>{const q=e.type||e.quality||'';if(!q)return;const lbl=evidenceQualityLabel(q);qualCounts[lbl]=(qualCounts[lbl]||0)+1});const sevChips=Object.keys(sevCounts).sort().map(s=>`<span class="badge">sev ${esc(s)} · ${esc(sevCounts[s])}</span>`).join('');const qualChips=Object.keys(qualCounts).map(q=>`<span class="badge">${esc(q)} · ${esc(qualCounts[q])}</span>`).join('');if(!sevChips&&!qualChips)return'';return`<div class="me-mirror-card"><h4>Pressure / evidence balance</h4>${sevChips?`<p class="small">Pressure severity</p><div class="me-mirror-chip-row">${sevChips}</div>`:''}${qualChips?`<p class="small">Evidence quality</p><div class="me-mirror-chip-row">${qualChips}</div>`:''}</div>`}
function meMirrorTensionsCardHtml(latest){if(!latest)return'';const list=meSafeParseJson(latest.contradictions_json,[]);if(!Array.isArray(list)||!list.length)return'';const items=list.slice(0,3).map(t=>{if(typeof t==='string')return t;if(t&&typeof t==='object')return[t.title,t.desc||t.description].filter(Boolean).join(': ');return''}).filter(Boolean);if(!items.length)return'';return`<div class="me-mirror-card"><h4>Tensions</h4><p class="small">Patterns the engine flagged in your answers, not facts about you.</p><ul class="me-mirror-tension-list">${items.map(t=>`<li>${esc(shortText(t,160))}</li>`).join('')}</ul></div>`}
function meMirrorQuestions(latest,evidenceCount){const qs=[];const pressureScore=Number(latest?.pressure_score)||0;const contradictions=meSafeParseJson(latest?.contradictions_json,[]);if(pressureScore>65)qs.push('What belief have I not pressure-tested yet?');if(Array.isArray(contradictions)&&contradictions.length>0)qs.push('Which tension would I investigate first?');if(evidenceCount<3)qs.push('What would change my mind?');return qs.slice(0,3)}
function meMirrorQuestionsCardHtml(latest,evidenceCount){const qs=meMirrorQuestions(latest,evidenceCount);if(!qs.length)return'';return`<div class="me-mirror-card"><h4>Questions to ask yourself</h4><ul class="me-mirror-question-list">${qs.map(q=>`<li>${esc(q)}</li>`).join('')}</ul></div>`}
function meMirrorHtml(data){const snapshots=data.belief_snapshots||[];if(!snapshots.length){return`<div class="panel"><h3>Belief Mirror</h3>${meMirrorGuardrailHtml()}<p class="small me-empty">Take the Belief Engine to start your Mirror.</p><button class="btn-mini" data-action="navBeliefEngine">Open Belief Engine →</button></div>`}const latest=snapshots[0];const previous=snapshots[1]||null;const evidenceCount=(data.evidence||[]).length;const cards=[meMirrorLatestCardHtml(latest),meMirrorDriftCardHtml(latest,previous),meMirrorCategoriesCardHtml(data.claims,data.truths),meMirrorBalanceCardHtml(data.pressure,data.evidence),meMirrorTensionsCardHtml(latest),meMirrorQuestionsCardHtml(latest,evidenceCount)].filter(Boolean);return`<div class="panel"><h3>Belief Mirror</h3>${meMirrorGuardrailHtml()}<div class="me-mirror-grid">${cards.join('')}</div></div>`}
// D-208D: private belief reflection cards — source habits, evidence strength habits,
// investigation activity. Reads only from already-loaded /api/my-humanx data (SELECT *
// on evidence includes source_type and evidence_strength; home_tests includes difficulty).
// Renders inside owner-only My HumanX view. No public surface. No identity labels.
function meReflectionMiniBar(label,count,total){const pct=total>0?Math.round(count/total*100):0;return`<div class="me-refl-row"><span class="me-refl-label">${esc(label)}</span><div class="me-refl-bar-wrap"><div class="me-refl-bar" style="width:${pct}%"></div></div><span class="me-refl-count">${esc(count)}</span></div>`}
function meReflectionSourceCardHtml(evidence){if(!evidence||!evidence.length)return'';const ST_ORDER=['personal_experience','news_report','expert_analysis','empirical_study','eyewitness','argument_opinion','scripture_tradition','social_media','myth_folklore','fiction_story','unknown'];const counts={};evidence.forEach(e=>{const st=String(e.source_type||e.sourceType||'unknown').trim().toLowerCase()||'unknown';counts[st]=(counts[st]||0)+1});const total=Object.values(counts).reduce((a,b)=>a+b,0);if(!total)return'';const rows=ST_ORDER.filter(k=>counts[k]).map(k=>meReflectionMiniBar(sourceTypeLabel(k),counts[k],total));if(!rows.length)return'';return`<div class="me-mirror-card me-refl-card"><h4>Source habits</h4><p class="small me-refl-note">You have used these source types most often. Origin does not prove truth.</p>${rows.join('')}<p class="small me-refl-private">Private reflection only — not a public identity label.</p></div>`}
function meReflectionStrengthCardHtml(evidence){if(!evidence||!evidence.length)return'';const ES_ORDER=['strong','moderate','weak','disputed','unknown'];const counts={};evidence.forEach(e=>{const es=String(e.evidence_strength||e.evidenceStrength||'unknown').trim().toLowerCase()||'unknown';counts[es]=(counts[es]||0)+1});const total=Object.values(counts).reduce((a,b)=>a+b,0);if(!total)return'';const rows=ES_ORDER.filter(k=>counts[k]).map(k=>meReflectionMiniBar(evidenceStrengthLabel(k),counts[k],total));if(!rows.length)return'';return`<div class="me-mirror-card me-refl-card"><h4>Evidence strength habits</h4><p class="small me-refl-note">How you tend to categorize evidence strength. This is self-assessment, not certainty.</p>${rows.join('')}<p class="small me-refl-private">Private reflection only — not a public identity label.</p></div>`}
function meReflectionActivityCardHtml(evidence,pressure,tests){const ev=evidence?evidence.length:0;const pr=pressure?pressure.length:0;const ts=tests?tests.length:0;if(!ev&&!pr&&!ts)return'';const total=ev+pr+ts;return`<div class="me-mirror-card me-refl-card"><h4>Investigation activity</h4><p class="small me-refl-note">What kinds of investigation actions you have added. More activity does not mean more correctness.</p>${meReflectionMiniBar('Evidence submitted',ev,total)}${meReflectionMiniBar('Pressure raised',pr,total)}${meReflectionMiniBar('Tests proposed',ts,total)}<p class="small me-refl-private">Private reflection only — not a public identity label.</p></div>`}
function meBeliefReflectionHtml(data){const evidence=data.evidence||[];const pressure=data.pressure||[];const tests=data.home_tests||[];const srcCard=meReflectionSourceCardHtml(evidence);const strCard=meReflectionStrengthCardHtml(evidence);const actCard=meReflectionActivityCardHtml(evidence,pressure,tests);const cards=[srcCard,strCard,actCard].filter(Boolean);if(!cards.length)return'';return`<div class="panel"><h3>Belief reflection</h3><p class="small me-mirror-guardrail">Private self-study based on how you interact with HumanX claims. Not a personality label or truth ranking.</p><p class="small me-mirror-guardrail">Belief patterns describe how you interact with claims. They are not a score of intelligence, morality, or truth.</p><div class="me-mirror-grid">${cards.join('')}</div></div>`}
// D-210B: private Reflection Avatar concept card — investigation habits only, never identity/rank/ideology
function meReflectionAvatarHtml(data){
  const evidence=data.evidence||[];
  const pressure=data.pressure||[];
  const tests=data.home_tests||[];
  const evCount=evidence.length;
  const prCount=pressure.length;
  const tsCount=tests.length;
  const total=evCount+prCount+tsCount;
  const guardrail='<p class="small me-avatar-note">Your avatar reflects investigation habits, not intelligence, morality, ideology, or truth.</p>';
  const privateNote='<p class="small me-avatar-note">Private concept only. It is not shown on your public profile.</p>';
  const emptyTransparencyHtml=`<details class="me-avatar-why"><summary class="me-avatar-why-summary">How this is formed</summary><div class="me-avatar-why-body"><p class="small">This is based only on your private HumanX activity patterns.</p><p class="small">It looks at investigation habits such as evidence added, pressure checks, and tests created.</p><p class="small">It is not a score, rank, diagnosis, ideology, morality label, intelligence label, or truth rating.</p><p class="small">It is private and is not shown on your public profile.</p></div></details>`;
  if(!total){return`<div class="panel me-avatar-card"><h3>Reflection avatar</h3><div class="me-avatar-symbol">◎</div><p class="small me-mirror-guardrail">Not enough private activity yet. Add evidence, pressure, or tests to form a reflection avatar.</p>${emptyTransparencyHtml}${guardrail}${privateNote}</div>`;}
  // Derive safe non-ranking habit descriptors from private data
  const chips=[];
  // Source diversity
  const stCounts={};
  evidence.forEach(e=>{const st=String(e.source_type||e.sourceType||'unknown').trim().toLowerCase()||'unknown';stCounts[st]=(stCounts[st]||0)+1;});
  const stTypes=Object.keys(stCounts).filter(k=>k!=='unknown');
  if(stTypes.length>=3)chips.push('Mixed-source investigator');
  else if(stTypes.length===2)chips.push('Source explorer');
  else if(evCount>0)chips.push('Evidence sorter');
  // Pressure engagement
  if(prCount>0&&prCount>=evCount*0.3)chips.push('Pressure mapper');
  else if(prCount>0)chips.push('Question builder');
  // Test-seeking
  if(tsCount>0)chips.push('Test planner');
  // Evidence strength diversity
  const esCounts={};
  evidence.forEach(e=>{const es=String(e.evidence_strength||e.evidenceStrength||'unknown').trim().toLowerCase()||'unknown';esCounts[es]=(esCounts[es]||0)+1;});
  const esTypes=Object.keys(esCounts).filter(k=>k!=='unknown');
  if(esTypes.length>=3)chips.push('Uncertainty friendly');
  // Derive a soft headline from dominant behaviour
  let headline='You tend to engage with claims through ';
  if(evCount>=prCount&&evCount>=tsCount)headline+='evidence gathering';
  else if(prCount>=evCount&&prCount>=tsCount)headline+='pressure and questioning';
  else headline+='testing and investigation';
  headline+=' activity.';
  // Cap chips at 4
  const chipHtml=chips.slice(0,4).map(c=>`<span class="me-avatar-chip">${esc(c)}</span>`).join('');
  // D-211A: transparency disclosure — why this card shows what it shows
  const transparencyHtml=`<details class="me-avatar-why"><summary class="me-avatar-why-summary">How this is formed</summary><div class="me-avatar-why-body"><p class="small">This is based only on your private HumanX activity patterns.</p><p class="small">It looks at investigation habits such as:</p><ul class="me-avatar-why-list"><li>Evidence added — ${esc(evCount)}</li><li>Pressure checks — ${esc(prCount)}</li><li>Tests created — ${esc(tsCount)}</li></ul><p class="small">It is not a score, rank, diagnosis, ideology, morality label, intelligence label, or truth rating.</p><p class="small">It is private and is not shown on your public profile.</p></div></details>`;
  return`<div class="panel me-avatar-card"><h3>Reflection avatar</h3><div class="me-avatar-symbol">◎</div><p class="small me-avatar-headline">${esc(headline)}</p><div class="me-avatar-chip-row">${chipHtml}</div>${transparencyHtml}${guardrail}${privateNote}</div>`;
}
function renderMeHtml(data){const u=data.user||{};const counts=data.counts||{};const claims=meFilterRows(data.claims);const truths=meFilterRows(data.truths);const evidence=meFilterRows(data.evidence);const pressure=meFilterRows(data.pressure);const snapshots=data.belief_snapshots||[];return`<div class="section-head"><h2>My HumanX</h2></div><p class="small" style="margin:0 0 12px">Your activity, contributions, and profile controls. Everything here is private by default — nothing is shared publicly until you enable a profile and save. Use <b>Profile Settings</b> below to create a shareable link, <b>Archive</b> to hide items from your view, and <b>Export</b> to download a local copy of your data.</p>${meAccountCardHtml(u)}${meProfileSettingsHtml(data)}<div class="panel me-counts-panel"><h3>My Content</h3>${meCountsRow('Claims',counts.claims)}${meCountsRow('Truths',counts.truths)}${meCountsRow('Evidence',counts.evidence)}${meCountsRow('Pressure',counts.pressure)}</div>${meFilterBarHtml()}<div class="panel"><h3>Recent Claims</h3><p class="small builder-field-note">Archive removes an item from your view and public profile — it is not permanently deleted from the system.</p>${meRecentClaimsHtml(meVisibleSlice('claims',claims))}${meShowAllControl('claims',claims.length)}</div><div class="panel"><h3>Belief Snapshots</h3>${meBeliefSnapshotsHtml(meVisibleSlice('snapshots',snapshots))}${meShowAllControl('snapshots',snapshots.length)}</div>${meMirrorHtml(data)}${meBeliefReflectionHtml(data)}${meReflectionAvatarHtml(data)}<div class="panel"><h3>Recent Truths</h3>${meRecentTruthsHtml(meVisibleSlice('truths',truths))}${meShowAllControl('truths',truths.length)}</div><div class="panel"><h3>Recent Evidence</h3>${meRecentEvidenceHtml(meVisibleSlice('evidence',evidence))}${meShowAllControl('evidence',evidence.length)}</div><div class="panel"><h3>Recent Pressure</h3>${meRecentPressureHtml(meVisibleSlice('pressure',pressure))}${meShowAllControl('pressure',pressure.length)}</div>`}
async function renderMe(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading My HumanX…</h2></div>';try{await ensureSession();meData=await api('/api/my-humanx');document.getElementById('main').innerHTML=renderMeHtml(meData)}catch(e){document.getElementById('main').innerHTML=`<div class="panel"><h3>My HumanX unavailable</h3><p class="small">${esc(e.message||e)}</p></div>`}}
function initReviewKb(){if(_reviewKbBound)return;_reviewKbBound=true;document.addEventListener('keydown',function(e){if(mode!=='review')return;const ae=document.activeElement;if(ae&&(ae.tagName==='INPUT'||ae.tagName==='TEXTAREA'||ae.tagName==='SELECT'||ae.isContentEditable))return;if(document.getElementById('hx-modal'))return;if(_reviewKbInFlight)return;const key=e.key;if(key==='Escape'&&inspectedReviewItem){e.preventDefault();inspectReviewItem(inspectedReviewItem.id);return;}if(!inspectedReviewItem)return;const id=inspectedReviewItem.id;const type=inspectedReviewItem.target_type||inspectedReviewItem.targetType||inspectedReviewItem.type||'claim';const vl=applyReviewSort(applyReviewFilter(reviewQueue.review||[]));const _i=vl.findIndex(v=>v.id===id);const _next=_i<vl.length-1?vl[_i+1]:null;const _prev=_i>0?vl[_i-1]:null;if(key===']'||key==='ArrowRight'){e.preventDefault();if(_next)inspectReviewItem(_next.id);return;}if(key==='['||key==='ArrowLeft'){e.preventDefault();if(_prev)inspectReviewItem(_prev.id);return;}if(key==='a'||key==='k'||key==='r'){e.preventDefault();if(key==='a'){if(pendingApproveReviewId===id){_reviewKbInFlight=true;const _advanceId=(_next?.id||_prev?.id||null);reviewDecisionUI(type,id,'public').then(()=>{if(_advanceId)inspectReviewItem(_advanceId);}).catch(()=>{}).finally(()=>{_reviewKbInFlight=false;});}else{requestApproveReview(id);}return;}if(key==='r'){if(pendingRejectReviewId===id){_reviewKbInFlight=true;const _advanceId=(_next?.id||_prev?.id||null);reviewDecisionUI(type,id,'rejected').then(()=>{if(_advanceId)inspectReviewItem(_advanceId);}).catch(()=>{}).finally(()=>{_reviewKbInFlight=false;});}else{requestRejectReview(id);}return;}_reviewKbInFlight=true;const _advanceId=(_next?.id||_prev?.id||null);reviewDecisionUI(type,id,'review').then(()=>{if(_advanceId)inspectReviewItem(_advanceId);}).catch(()=>{}).finally(()=>{_reviewKbInFlight=false;});}});}
async function renderReview(){document.body.classList.remove('study-mode');initReviewKb();document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';const token=adminToken();document.getElementById('main').innerHTML=`<div class="review-page"><div class="review-header review-admin-bar"><div class="review-header-left"><h2>Review Queue</h2><span class="badge b-red">admin only</span></div><div class="review-token-form"><input id="adminToken" type="password" placeholder="Admin token" value="${esc(token)}" autocomplete="off"><button class="primary" data-action="saveAdminTokenAndLoadReview">Load Queue</button><button data-action="clearAdminToken">Clear Token</button></div></div>${token?renderAdminInvitePanel():''}<div id="reviewList" class="grid"><div class="panel">${token?'Loading review queue…':'Review is owner-only. Enter the admin token to load the queue.'}</div></div></div>`;if(token){try{await loadReviewQueue();renderReviewList()}catch(e){document.getElementById('reviewList').innerHTML=`<div class="panel"><h3>Review unavailable</h3><p class="small">${esc(e.message||e)}</p><p class="small">Check the admin token above, re-enter it if needed, then reload the queue.</p></div>`}}}

// D-136D: admin-only invite-code creator panel — visible only inside the
// admin-token-gated Review area. Never reachable from the public account
// panel (D-136C), which only ever calls /api/me and /api/auth/invite/redeem.
function renderAdminInvitePanel(){return`<div class="panel compact-form admin-invite-panel"><h3 class="hx-form-head">Create Invite Code</h3><p class="small admin-invite-note">Manual-code invite only — no email is sent. Share the generated code with the recipient yourself.</p><input id="adminInviteNote" name="adminInviteNote" placeholder="Note (e.g. recipient name)"><input id="adminInviteEmailHint" name="adminInviteEmailHint" placeholder="Email hint (optional)"><button class="primary" data-action="createInviteCodeUI">Create Invite Code</button><div id="adminInviteResult" class="admin-invite-result"></div></div>`}
async function createInviteCodeUI(){if(!adminToken()){toast('Admin token required to create invite codes.');return}const note=document.getElementById('adminInviteNote')?.value.trim()||'';const emailHint=document.getElementById('adminInviteEmailHint')?.value.trim()||'';try{const data=await api('/api/auth/invite/create',{method:'POST',headers:adminHeaders(),body:JSON.stringify({note:note||undefined,emailHint:emailHint||undefined})});const code=data.code||data.invite?.code||'';const createdAt=data.invite?.created_at?new Date(data.invite.created_at).toLocaleString():'';const resultEl=document.getElementById('adminInviteResult');if(resultEl)resultEl.innerHTML=`<div class="admin-invite-code-row"><code class="admin-invite-code">${esc(code)}</code><button class="btn-mini" data-action="copyAdminInviteCode" data-id="${esc(code)}">Copy code</button></div>${createdAt?`<p class="small admin-invite-created">Created: ${esc(createdAt)}</p>`:''}`;toast('Invite code created.')}catch(e){toast(e.message||'Invite code creation failed.')}}
function copyAdminInviteCode(code){if(navigator.clipboard?.writeText){navigator.clipboard.writeText(code).then(()=>toast('Invite code copied.')).catch(()=>toast('Copy failed — select the code manually.'))}else{toast('Copy failed — select the code manually.')}}
function isTruthDerivedClaim(item){return String(item.type||'').toLowerCase()==='truth-derived'||String(item.claim_type||item.claimType||'').toLowerCase()==='truth-derived';}
function isClaimCategoryEcho(item){const cl=String(item.claim||'').trim().toLowerCase();const ca=String(item.category||'').trim().toLowerCase();if(!cl||!ca)return false;return cl===ca;}
function isLikelyBorderlineDerivedClaim(item){if(!isTruthDerivedClaim(item))return false;if(isClaimCategoryEcho(item))return true;const cl=String(item.claim||'').trim();if(cl.length>=2&&cl.length<=40&&cl===cl.toUpperCase()&&/[A-Z]/.test(cl))return true;const es=item.evidence_score??item.evidenceScore??null;return es!==null&&es<=10;}
function applyReviewFilter(list){const f=reviewStateFilter||'review';if(f==='all')return list;if(f==='reported')return list.filter(i=>(i.report_count||i.reportCount||0)>0);if(f==='similar')return list.filter(i=>!!i.near_duplicate_of);if(f==='pressure')return list.filter(i=>(i.target_type||i.targetType||i.type||'claim')==='pressure');if(f==='quality')return list.filter(i=>{const tp=i.target_type||i.targetType||i.type||'claim';if(tp==='truth'||tp==='evidence'||tp==='pressure')return false;return claimQualityHints(cleanClaimLabel(i.claim||'')).length>0;});if(f==='duplicate')return list.filter(i=>!!(i.duplicate_of||i.duplicateOf||i.near_duplicate_of||i.nearDuplicateOf));if(f==='demo-test')return list.filter(i=>isSuspectedTestArtefact(i));if(f==='truth-derived')return list.filter(isTruthDerivedClaim);return list.filter(i=>(i.review_state||i.reviewState||'review')===f)}
function reviewAge(dateVal){const d=new Date(dateVal||Date.now());const diff=Date.now()-d.getTime();if(diff<60000)return'just now';if(diff<3600000)return Math.floor(diff/60000)+'m ago';if(diff<86400000)return Math.floor(diff/3600000)+'h ago';if(diff<604800000)return Math.floor(diff/86400000)+'d ago';if(diff<2592000000)return Math.floor(diff/604800000)+'w ago';return d.toLocaleDateString();}
function applyReviewSort(list){const s=reviewSortOrder||'newest';const copy=[...list];if(s==='oldest')return copy.sort((a,b)=>new Date(a.updated_at||a.updatedAt||a.created_at||0)-new Date(b.updated_at||b.updatedAt||b.created_at||0));if(s==='reported')return copy.sort((a,b)=>{const rd=(b.report_count||b.reportCount||0)-(a.report_count||a.reportCount||0);return rd!==0?rd:new Date(b.updated_at||b.updatedAt||b.created_at||0)-new Date(a.updated_at||a.updatedAt||a.created_at||0);});if(s==='similar')return copy.sort((a,b)=>{const sd=(b.near_duplicate_of?1:0)-(a.near_duplicate_of?1:0);return sd!==0?sd:new Date(b.updated_at||b.updatedAt||b.created_at||0)-new Date(a.updated_at||a.updatedAt||a.created_at||0);});if(s==='quality')return copy.sort((a,b)=>{const ha=claimQualityHints(cleanClaimLabel(a.claim||a.statement||'')).length;const hb=claimQualityHints(cleanClaimLabel(b.claim||b.statement||'')).length;return hb!==ha?hb-ha:new Date(b.updated_at||b.updatedAt||b.created_at||0)-new Date(a.updated_at||a.updatedAt||a.created_at||0);});return copy.sort((a,b)=>new Date(b.updated_at||b.updatedAt||b.created_at||0)-new Date(a.updated_at||a.updatedAt||a.created_at||0));}
function setReviewSort(s){reviewSortOrder=s||'newest';renderReviewList()}
function claimQualityHints(text){if(!text||text.trim().length<3)return[];const t=text.trim();const lo=t.toLowerCase();const hints=[];if(t.length<20)hints.push({code:'too-short',msg:'Very short — add a specific quantity, date, or outcome to make it testable.'});if(/^(i think|i believe|in my opinion|it'?s obvious|clearly |obviously )/i.test(lo))hints.push({code:'opinion',msg:'Sounds like an opinion — reframe as an observable, falsifiable statement.'});if(/\b(always|never)\b/.test(lo)&&t.length<60)hints.push({code:'absolute',msg:'"Always"/"never" is hard to falsify — consider a specific time range or context.'});if(/everyone knows|everybody knows/i.test(lo))hints.push({code:'common-knowledge',msg:'"Everyone knows" is not evidence — state what is specifically claimed.'});if(/they('re| are)? hiding|they don'?t want (you|us) to know|\bwake up\b.*\b(sheeple|people)\b|\bdo your (own )?research\b/i.test(lo))hints.push({code:'slogan',msg:'Slogan or vague framing — name who, what, and when to make this testable.'});if(/\b(the government|the media|the elite|the establishment|big pharma|the deep state)\b/i.test(lo)&&!/\d/.test(lo)&&t.length<80)hints.push({code:'vague-actor',msg:'Broad actor — name the specific agency, official, or publication.'});if(/\b(evil|corrupt)\b/i.test(lo)&&!/\b(found|proven|charged|convicted|documented|report(ed)?)\b/i.test(lo))hints.push({code:'moral',msg:'Moral label without documented act — name the specific action or finding.'});if(/\b(everything is|nothing is|all people|everyone is|nobody is|no one is)\b/i.test(lo))hints.push({code:'universal',msg:'Universal scope is unfalsifiable — narrow to a specific group or context.'});return hints;}
function updateClaimQualityHints(){const el=document.getElementById('cClaimHints');if(!el)return;const text=(document.getElementById('cClaim')?.value||'').trim();if(text.length<10){el.innerHTML='';return;}const hints=claimQualityHints(text);if(!hints.length){el.innerHTML='';return;}el.innerHTML='<div class="cq-hint-bar"><span class="cq-hint-label">Quality hints <span class="cq-hint-advisory">(advisory — not blocking)</span></span><ul class="cq-hint-list">'+hints.map(h=>`<li>${esc(h.msg)}</li>`).join('')+'</ul></div>';}
function renderReviewFilterBar(list){const s=i=>(i.review_state||i.reviewState||'review');const counts={review:list.filter(i=>s(i)==='review').length,public:list.filter(i=>s(i)==='public').length,rejected:list.filter(i=>s(i)==='rejected').length,reported:list.filter(i=>(i.report_count||i.reportCount||0)>0).length,similar:list.filter(i=>!!i.near_duplicate_of).length,quality:list.filter(i=>{const tp=i.target_type||i.targetType||i.type||'claim';if(tp==='truth'||tp==='evidence'||tp==='pressure')return false;return claimQualityHints(cleanClaimLabel(i.claim||'')).length>0;}).length,pressure:list.filter(i=>(i.target_type||i.targetType||i.type||'claim')==='pressure').length,'duplicate':list.filter(i=>!!(i.duplicate_of||i.duplicateOf||i.near_duplicate_of||i.nearDuplicateOf)).length,'demo-test':list.filter(isSuspectedTestArtefact).length,'truth-derived':list.filter(isTruthDerivedClaim).length,all:list.length};const defs=[['review','Pending'],['public','Public'],['rejected','Rejected'],['reported','Reported'],['similar','~Similar'],['quality','~Quality'],['pressure','Pressure'],['duplicate','Dupes'],['demo-test','Demo/Test'],['truth-derived','Truth-Derived'],['all','All']];const chips=defs.map(([f,label])=>{const n=counts[f];const active=reviewStateFilter===f;return`<button class="review-filter-chip${active?' review-filter-chip-active':''}" data-action="setReviewFilter" data-value="${f}">${label}${n>0?` <span class="review-filter-count">${n}</span>`:''}</button>`}).join('');const help=reviewFilterHelpText(reviewStateFilter);const rejectedCount=counts.rejected||0;const showCleanupHint=(rejectedCount>0||(reviewQueue.archived_total||0)>0)&&adminToken();const cleanupHint=showCleanupHint?`<p class="review-cleanup-hint">Cleanup: open <b>Rejected</b> → Inspect a smoke/test artefact → <b>Archive test artefact</b>.</p>`:'';return`<div class="review-filter-bar review-filter-compact" style="grid-column:1/-1"><div class="review-filter-chips">${chips}</div><div class="review-sort-bar"><label class="review-sort-label">Sort:</label><select class="review-sort-select" onchange="setReviewSort(this.value)"><option value="newest"${reviewSortOrder==='newest'?' selected':''}>Newest first</option><option value="oldest"${reviewSortOrder==='oldest'?' selected':''}>Oldest first</option><option value="reported"${reviewSortOrder==='reported'?' selected':''}>Reported first</option><option value="similar"${reviewSortOrder==='similar'?' selected':''}>~Similar first</option><option value="quality"${reviewSortOrder==='quality'?' selected':''}>~Quality first</option></select></div>${help?`<p class="review-filter-help">${esc(help)}</p>`:''}${cleanupHint}</div>`}
function setReviewFilter(f){reviewStateFilter=f||'review';renderReviewList()}
function renderReviewInspectContext(item){const type=item.target_type||item.targetType||item.type||'claim';const isTruth=type==='truth';const isEvidence=type==='evidence';const isPressure=type==='pressure';const state=item.review_state||item.reviewState||'review';const title=isEvidence?(item.title||'Evidence'):isPressure?(item.title||'Pressure Point'):isTruth?(item.statement||'Truth'):(item.claim||'Claim');const stateClr=state==='public'?'b-green':state==='rejected'?'b-red':'b-yellow';const rows=[];if(!isTruth&&!isEvidence&&!isPressure){const es=item.evidence_score??item.evidenceScore??null;const ts=item.testability??null;const sv=item.survivability??null;if(es!=null)rows.push(['Evidence',`${es}/100`]);if(ts!=null)rows.push(['Testability',`${ts}/100`]);if(sv!=null)rows.push(['Survivability',`${sv}/100`]);if(item.category)rows.push(['Category',item.category]);if(item.type)rows.push(['Claim Type',item.type]);if(item.status)rows.push(['Status',item.status]);if(item.handle)rows.push(['Submitted By',item.handle]);if(item.user_id)rows.push(['User ID',item.user_id]);if(item.source_truth_id)rows.push(['Source Truth',item.source_truth_id]);}if(isTruth){const rep=item.repetition_score??item.repetitionScore??null;if(rep!=null)rows.push(['Repetitions',String(rep)]);if(item.category)rows.push(['Category',item.category]);if(item.origin)rows.push(['Origin',item.origin]);if(item.handle)rows.push(['Submitted By',item.handle]);if(item.user_id)rows.push(['User ID',item.user_id]);}if(isEvidence||isPressure){if(item.stance)rows.push(['Stance',item.stance]);if(item.severity)rows.push(['Severity',`${item.severity}/5`]);if(item.quality)rows.push(['Quality',item.quality]);}const reports=item.report_count||item.reportCount||0;if(reports>0)rows.push(['Reports',`⚑ ${reports}`]);const created=item.created_at||item.createdAt||null;if(created)rows.push(['Created',new Date(created).toLocaleDateString()]);const updated=item.updated_at||item.updatedAt||null;if(updated)rows.push(['Updated',new Date(updated).toLocaleDateString()]);const rowsHtml=rows.map(([k,v])=>`<div class="rctx-row"><span class="rctx-label">${esc(k)}</span><span class="rctx-val">${esc(v)}</span></div>`).join('');let builderCtxHtml='';const sc=item.claimBuilderContext||item.claim_builder_context||null;if(sc&&sc.rawText){const flags=Array.isArray(sc.systemFlags)?sc.systemFlags:[];const trunc=(s,n)=>String(s||'').slice(0,n)+(String(s||'').length>n?'…':'');const parts=[];if(sc.rawText)parts.push(`<div class="rctx-bc-row"><b>User text</b><p>${esc(trunc(sc.rawText,100))}</p></div>`);if(sc.whyUserThinksThis)parts.push(`<div class="rctx-bc-row"><b>Why</b><p>${esc(trunc(sc.whyUserThinksThis,80))}</p></div>`);if(sc.scope)parts.push(`<div class="rctx-bc-row"><b>Scope</b><p>${esc(trunc(sc.scope,60))}</p></div>`);if(sc.pressureOrFalsifier)parts.push(`<div class="rctx-bc-row"><b>Falsifier</b><p>${esc(trunc(sc.pressureOrFalsifier,60))}</p></div>`);if(flags.length)parts.push(`<div class="rctx-bc-row"><b>Flags</b><p class="rctx-flags">${flags.map(f=>`<span class="badge b-yellow">${esc(String(f))}</span>`).join(' ')}</p></div>`);builderCtxHtml=`<div class="rctx-builder"><div class="rctx-builder-head"><span class="badge b-blue">Claim Builder</span><span class="badge b-green">structured</span></div>${parts.join('')}</div>`;}else{const ctx=parseClaimBuilderContext(item.initialEvidence||item.initial_evidence||item.body||item.note||'');if(ctx){const trunc=(s,n)=>String(s||'').slice(0,n)+(String(s||'').length>n?'…':'');builderCtxHtml=`<div class="rctx-builder"><div class="rctx-builder-head"><span class="badge b-blue">Claim Builder</span><span class="badge b-yellow">legacy</span></div>${ctx.original?`<div class="rctx-bc-row"><b>User text</b><p>${esc(trunc(ctx.original,100))}</p></div>`:''}${ctx.why?`<div class="rctx-bc-row"><b>Why</b><p>${esc(trunc(ctx.why,80))}</p></div>`:''}</div>`;}else if(!isTruth&&!isEvidence&&!isPressure){builderCtxHtml=`<div class="rctx-builder rctx-builder-missing"><span class="badge">no builder context</span></div>`;}}const shortTitle=cleanClaimLabel(title);const displayTitle=shortTitle.slice(0,80)+(shortTitle.length>80?'…':'');return`<div class="rctx-panel"><div class="rctx-head"><span class="badge ${isEvidence?'b-purple':isPressure?'b-orange':isTruth?'b-yellow':'b-blue'}">${esc(type)}</span><span class="badge ${stateClr}">${esc(state)}</span></div><p class="rctx-title">${esc(displayTitle)}</p>${rowsHtml?`<div class="rctx-rows">${rowsHtml}</div>`:''}${builderCtxHtml}</div>`}
function renderReviewOverviewStrip(all){if(!all.length)return'';const st=i=>i.review_state||i.reviewState||'review';const tp=i=>i.target_type||i.targetType||i.type||'claim';const pending=all.filter(i=>st(i)==='review').length;const pub=all.filter(i=>st(i)==='public').length;const rejected=all.filter(i=>st(i)==='rejected').length;const claims=all.filter(i=>tp(i)==='claim').length;const truths=all.filter(i=>tp(i)==='truth').length;const evidence=all.filter(i=>tp(i)==='evidence').length;const pressure=all.filter(i=>tp(i)==='pressure').length;const pills=[`<span class="rov-pill rov-pending">${pending} pending</span>`,pub>0?`<span class="rov-pill rov-pub">${pub} pub</span>`:'',rejected>0?`<span class="rov-pill rov-rej">${rejected} rejected</span>`:'',`<span class="rov-sep"></span>`,claims>0?`<span class="rov-pill">${claims} claim${claims!==1?'s':''}</span>`:'',truths>0?`<span class="rov-pill">${truths} truth${truths!==1?'s':''}</span>`:'',evidence>0?`<span class="rov-pill">${evidence} ev</span>`:'',pressure>0?`<span class="rov-pill rov-pressure">${pressure} pressure</span>`:''  ].filter(Boolean).join('');return`<div class="review-overview-strip" style="grid-column:1/-1">${pills}</div>`;}
function renderReviewList(){const all=reviewQueue.review||[];const list=applyReviewSort(applyReviewFilter(all));if(inspectedReviewItem&&!list.find(i=>i.id===inspectedReviewItem.id))inspectedReviewItem=null;if(pendingRejectReviewId&&!list.find(i=>i.id===pendingRejectReviewId))pendingRejectReviewId=null;if(pendingCleanupReviewId&&!list.find(i=>i.id===pendingCleanupReviewId))pendingCleanupReviewId=null;const bar=renderReviewFilterBar(all);const overview=renderReviewOverviewStrip(all);const audit=renderReviewAuditSummary(all);const panel=inspectedReviewItem?renderReviewInspectPanel(inspectedReviewItem):'';const empty=`<div class="panel review-empty-state" style="grid-column:1/-1">${reviewEmptyText(reviewStateFilter)}</div>`;document.getElementById('reviewList').innerHTML=bar+overview+audit+panel+(list.map(reviewCard).join('')||empty);const cf=document.getElementById('casefile');if(cf)cf.innerHTML=inspectedReviewItem?renderReviewInspectContext(inspectedReviewItem):helperText();}
function reviewCard(item){const type=item.target_type||item.targetType||item.type||'claim';const isTruth=type==='truth';const isEvidence=type==='evidence';const isPressure=type==='pressure';const id=item.id;const title=isEvidence?(item.title||'Evidence'):isPressure?(item.title||'Pressure Point'):isTruth?(item.statement||'Truth'):(item.claim||'Claim');const state=item.review_state||item.reviewState||'review';const stateClr=state==='public'?'b-green':state==='rejected'?'b-red':'b-yellow';const cardMod=state==='public'?'review-card-public':state==='rejected'?'review-card-rejected':state==='duplicate'?'review-card-duplicate':'review-card-pending';const similarMod=item.near_duplicate_of?' review-card-similar':'';const pressureMod=isPressure?' review-card-pressure':'';const qhints=(!isTruth&&!isEvidence&&!isPressure)?claimQualityHints(cleanClaimLabel(title)):[];const isSelected=!!(inspectedReviewItem&&inspectedReviewItem.id===id);const isPendingReject=pendingRejectReviewId===id;const isPendingApprove=pendingApproveReviewId===id;const reports=item.report_count||item.reportCount||0;const scoreHint=isEvidence?(item.stance||'evidence'):isTruth?`rep ×${item.repetition_score||1}`:`ev:${item.evidence_score??0} ts:${item.testability??'-'} sv:${item.survivability??'-'}`;const metaParts=isEvidence?[item.stance,item.quality].filter(Boolean):isPressure?['severity '+(item.severity||1)+'/5',item.handle?'by '+item.handle:null,item.parent_claim?item.parent_claim.slice(0,60)+(item.parent_claim.length>60?'…':''):null].filter(Boolean):[item.category||'general',isTruth?(item.origin||null):(item.status||null),scoreHint].filter(Boolean);const updated=reviewAge(item.updated_at||item.updatedAt||item.created_at||Date.now());const rejectBtn=isPendingReject?`<span class="review-reject-confirm-msg">Reject? It will not become public.</span><button class="btn-reject-confirm" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','rejected')">Confirm Reject</button><button class="btn-reject-cancel" onclick="cancelRejectReview()">Cancel</button>`:`<button class="btn-reject" title="Hide this item permanently" onclick="requestRejectReview('${esc(id)}')">Reject</button>`;const approveBtn=isPendingApprove?`<span class="review-approve-confirm-msg">Approve this item? It will become public.</span><button class="btn-approve-confirm" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','public')">Confirm Approve</button><button class="btn-approve-cancel" onclick="cancelApproveReview()">Cancel</button>`:`<button class="btn-approve" title="Approve and publish to all users" onclick="requestApproveReview('${esc(id)}')">Approve</button>`;const origin=reviewItemOriginLabel(item);const originChip=origin&&origin!=='user'?`<span class="rc-chip rc-chip-origin rc-chip-origin-${origin.replace(/[^a-z]/g,'')}">${esc(origin)}</span>`:'';const handleChip=item.handle?`<span class="rc-chip rc-chip-handle">${esc(item.handle)}</span>`:'';const dupOf=item.duplicate_of||item.duplicateOf||null;const dupChip=dupOf?`<span class="rc-chip rc-chip-dup" title="duplicate of ${esc(dupOf)}">dup</span>`:'';const lockedChip=(item.status_locked||item.statusLocked)?`<span class="rc-chip rc-chip-locked" title="Status score locked">🔒</span>`:'';const chipsRow=(originChip||handleChip||dupChip||lockedChip)?`<div class="review-card-chips">${originChip}${handleChip}${dupChip}${lockedChip}</div>`:'';const builderChip=(!isTruth&&!isEvidence&&!isPressure)?((item.claimBuilderContext?.rawText||item.claim_builder_context?.rawText)?`<span class="badge b-blue rc-builder-chip">Builder</span>`:((item.initialEvidence||item.initial_evidence||'').includes('Claim Builder context:')?`<span class="badge rc-builder-chip">Builder*</span>`:'')):'' ;return`<article data-review-id="${esc(id)}" class="card review-card review-card-compact ${cardMod}${similarMod}${pressureMod}${isTruth?' review-card-truth':''}${isSelected?' review-card-selected':''}${isPendingReject?' review-card-reject-pending':''}"><div class="review-card-head"><span class="badge ${isEvidence?'b-purple':isPressure?'b-orange':isTruth?'b-yellow':'b-blue'}">${esc(type)}</span><span class="badge ${stateClr}">${esc(state)}</span>${reports>0?`<span class="badge b-red">⚑ ${esc(reports)} report${reports===1?'':'s'}</span>`:''} ${item.near_duplicate_of?`<span class="badge b-similar">~similar</span>`:''} ${qhints.length?`<span class="badge b-quality" title="${esc(qhints.map(h=>h.msg).join(' · '))}">needs sharpening</span>`:''} ${isTruthDerivedClaim(item)?`<span class="badge b-truth-derived">truth-derived</span>`:''} ${isTruthDerivedClaim(item)&&isClaimCategoryEcho(item)?`<span class="badge b-category-echo" title="Category echoes claim text — do not approve without checking parent Truth">category-echo</span>`:''} ${isLikelyBorderlineDerivedClaim(item)?`<span class="badge b-borderline-origin" title="Heuristic: may derive from a borderline Truth — advisory only">? borderline origin</span>`:''}${builderChip}</div>${chipsRow}${item.latest_report_reason?`<p class="review-reason-tag">Reason: ${esc(item.latest_report_reason)}</p>`:''}<h3 class="review-card-title">${esc(cleanClaimLabel(title))}</h3><p class="small review-card-meta">${metaParts.map(esc).join(' · ')}</p><p class="small review-card-date">Updated ${esc(updated)}</p><div class="review-actions"><button class="btn-inspect${isSelected?' btn-inspect-active':''}" title="Inspect all available fields" onclick="inspectReviewItem('${esc(id)}')">${isSelected?'▲ Inspecting':'Inspect'}</button>${isSelected?'':`${approveBtn}<button class="btn-keep" title="Leave in the pending queue for now" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','review')">Keep Pending</button>${rejectBtn}`}</div></article>`}
function inspectReviewItem(id){const item=(reviewQueue.review||[]).find(i=>i.id===id)||null;inspectedReviewItem=(inspectedReviewItem&&inspectedReviewItem.id===id)?null:item;renderReviewList();if(inspectedReviewItem)document.querySelector('.review-inspect-panel')?.scrollIntoView({behavior:'smooth',block:'start'});}
function requestRejectReview(id){pendingRejectReviewId=(pendingRejectReviewId===id)?null:id;renderReviewList()}
function cancelRejectReview(){pendingRejectReviewId=null;renderReviewList()}
function requestApproveReview(id){pendingApproveReviewId=(pendingApproveReviewId===id)?null:id;renderReviewList()}
