function detectPacketStaleness(){if(!lastPacket||!selected)return null;let meta;try{meta=JSON.parse(lastPacket)}catch(e){return null}if(!meta.packet_id)return null;const w=[];if(meta.evidence_count!=null&&meta.evidence_count!==(selected.evidence||[]).length)w.push('evidence count changed');if(meta.pressure_count!=null&&meta.pressure_count!==(selected.pressure||[]).length)w.push('pressure count changed');if(meta.test_count!=null&&meta.test_count!==(selected.tests||[]).length)w.push('test count changed');if(meta.generated_at){const ageMs=Date.now()-new Date(meta.generated_at).getTime();if(ageMs>3600000)w.push('packet is '+Math.floor(ageMs/3600000)+'h old');}return w.length?w.join(' · '):null}
async function generateRunPack(){if(!selected)return toast('Open a claim first');const provenance=buildProvenanceMeta(selected);try{const data=await api('/api/runpack',{method:'POST',body:JSON.stringify({claimId:selected.id})});const _wp=!!(data.packet&&data.packet.packet_id);const _mp=_wp?{humanx_app_version:'v10'}:provenance;lastPacket=JSON.stringify({...data.packet,..._mp},null,2);lastPacketIsFallback=false}catch(e){lastPacket=JSON.stringify({...provenance,is_fallback:true,legacy_aip_version:'1.1',aip_version:'1.1',packet_type:'runpack_task',app:'HumanX',mode:'claim-pressure-analysis',no_owner_api_used:true,payload:safeRunPackClaim(selected)},null,2);lastPacketIsFallback=true}lastPacketClaimId=selected.id;lastPacketMeta=provenance;const statusEl=document.getElementById('aip-status');if(statusEl){statusEl.textContent='RunPack ready — copy it here or open the RunPack tab for full JSON and download.';statusEl.classList.add('runpack-side-status-ready');}if(mode==='export')renderExport();toast('RunPack ready — copy it into your AI')}
